(function() {
  'use strict';

  const BIOS = {"AOOS": {
      en: '"Citizen of the Cosmos". Rising <b>Psychedelic Dark Progressive</b> producer signed to Padang Records, AOOS blends dark, trippy and atmospheric sounds with groovy basslines and driven rhythms — hypnotic, captivating music. Wide inspiration: Psytrance, Techno, Breakbeat and Ambient — crafting a sonic landscape that is at once otherworldly and deeply emotional, taking listeners on journeys through the depths of the mind, exploring the mysteries of consciousness and the inner workings of the human psyche. Live performance is central to the identity. <b>On Padang Records:</b> <b>Cosmic Visitors</b> (10/2024) and <b>Spaceman</b> (03/2025); featured on the VAs <b>The Nightmare</b> (Funboosting DarkSide), <b>Nyctophilia II</b> (The Pinwheel) and <b>Reborn</b> (Let There Be Dark).',
      es: '"Citizen of the Cosmos". Productor en ascenso de <b>Psychedelic Dark Progressive</b> firmado con Padang Records, AOOS mezcla sonidos oscuros, trippy y atmosféricos con basslines groovy y ritmos dirigidos — música hipnótica y cautivante. Inspiración amplia: Psytrance, Techno, Breakbeat y Ambient — creando un paisaje sónico que es a la vez de otro mundo y profundamente emocional, llevando al oyente por viajes a través de las profundidades de la mente, explorando los misterios de la consciencia y el funcionamiento interno de la psique humana. La performance en vivo es parte central de la identidad. <b>En Padang Records:</b> <b>Cosmic Visitors</b> (10/2024) y <b>Spaceman</b> (03/2025); presente en las VAs <b>The Nightmare</b> (Funboosting DarkSide), <b>Nyctophilia II</b> (The Pinwheel) y <b>Reborn</b> (Let There Be Dark).',
      de: '"Citizen of the Cosmos". Aufstrebender <b>Psychedelic Dark Progressive</b>-Produzent bei Padang Records, AOOS mischt düstere, trippige und atmosphärische Sounds mit grooviger Basslines und treibenden Rhythmen — hypnotische, fesselnde Musik. Breite Inspiration: Psytrance, Techno, Breakbeat und Ambient — er erschafft eine Klanglandschaft, die zugleich jenseitig und zutiefst emotional ist und Hörer auf Reisen in die Tiefen des Geistes mitnimmt, die Mysterien des Bewusstseins und das innere Wirken der menschlichen Psyche erforschend. Live-Performance ist zentraler Teil der Identität. <b>Auf Padang Records:</b> <b>Cosmic Visitors</b> (10/2024) und <b>Spaceman</b> (03/2025); auf den VAs <b>The Nightmare</b> (Funboosting DarkSide), <b>Nyctophilia II</b> (The Pinwheel) und <b>Reborn</b> (Let There Be Dark).',
      fr: '"Citizen of the Cosmos". Producteur émergent de <b>Psychedelic Dark Progressive</b> signé chez Padang Records, AOOS mêle sons sombres, trippy et atmosphériques à des basslines groovy et des rythmes dirigés — une musique hypnotique et captivante. Inspiration large : Psytrance, Techno, Breakbeat et Ambient — il façonne un paysage sonore à la fois extraterrestre et profondément émotionnel, embarquant les auditeurs dans des voyages au cœur de l\'esprit, explorant les mystères de la conscience et le fonctionnement intérieur de la psyché humaine. La performance live est au centre de l\'identité. <b>Sur Padang Records :</b> <b>Cosmic Visitors</b> (10/2024) et <b>Spaceman</b> (03/2025) ; présent sur les VAs <b>The Nightmare</b> (Funboosting DarkSide), <b>Nyctophilia II</b> (The Pinwheel) et <b>Reborn</b> (Let There Be Dark).',
      ja: '「Citizen of the Cosmos」。Padang Records 所属の新進気鋭の <b>Psychedelic Dark Progressive</b> プロデューサー、AOOS はダーク、トリッピー、アトモスフェリックなサウンドをグルーヴィーなベースラインと推進力のあるリズムに融合する — 催眠的で魅力的な音楽。幅広いインスピレーション：Psytrance、Techno、Breakbeat、Ambient — 異世界的でありながら深く感情的なサウンドスケープを生み出し、聴く者を心の深淵への旅へと誘い、意識の神秘と人間の心の内なる働きを探求させる。ライブ・パフォーマンスはアイデンティティの中心。<b>Padang Records から：</b><b>Cosmic Visitors</b>（2024年10月）、<b>Spaceman</b>（2025年3月）。VA <b>The Nightmare</b>（Funboosting DarkSide）、<b>Nyctophilia II</b>（The Pinwheel）、<b>Reborn</b>（Let There Be Dark）に参加。'
    },
    "Aru": {
      en: '<b>Aru</b>, Peru. Live act and producer from the Padang Records family. Tracks on SoundCloud: <b>KIMURI</b> (12/2024), <b>TOTEM</b> (11/2020), <b>SOUR DIESEL</b> (03/2020) — soundscapes that range from dark progressive to psy minimal.',
      es: '<b>Aru</b>, Perú. Live act y productor de la familia Padang Records. Pistas en SoundCloud: <b>KIMURI</b> (12/2024), <b>TOTEM</b> (11/2020), <b>SOUR DIESEL</b> (03/2020) — soundscapes que recorren desde dark progressive hasta psy minimal.',
      de: '<b>Aru</b>, Peru. Live-Act und Produzent aus der Padang-Records-Familie. Tracks auf SoundCloud: <b>KIMURI</b> (12/2024), <b>TOTEM</b> (11/2020), <b>SOUR DIESEL</b> (03/2020) — Soundscapes von Dark Progressive bis Psy Minimal.',
      fr: '<b>Aru</b>, Pérou. Live act et producteur de la famille Padang Records. Titres sur SoundCloud : <b>KIMURI</b> (12/2024), <b>TOTEM</b> (11/2020), <b>SOUR DIESEL</b> (03/2020) — soundscapes allant du dark progressive au psy minimal.',
      ja: '<b>Aru</b>、ペルー。Padang Records ファミリーのライブアクト／プロデューサー。SoundCloud 配信曲：<b>KIMURI</b>（2024年12月）、<b>TOTEM</b>（2020年11月）、<b>SOUR DIESEL</b>（2020年3月）— ダーク・プログレッシブからサイ・ミニマルまで広がるサウンドスケープ。'
    },"Akudama": {
      en: '<b>James Toa</b>, New Zealand. Akudama sculpts shadows into sound — psytech and dark progressive fused with industrial and mechanical soundscapes. <b>Dark aural alchemy</b> and storytelling hidden inside tonal cryptography: every track is a cipher. The music flows through deep rolling basslines, hypnotic atmospheres and glitch-driven textures; a passion for dark, groovy and psychedelic sound builds immersive journeys, pulling listeners into the shadows of rhythm and resonance. Part of the Padang Records family. Booking: akudamamusicc@gmail.com.',
      es: '<b>James Toa</b>, Nueva Zelanda. Akudama esculpe sombras en forma de sonido — psytech y dark progressive fundidos con soundscapes industriales y mecánicos. <b>Dark aural alchemy</b> y storytelling escondidos en criptografía tonal: cada track es una cifra. La música fluye a través de basslines profundas y rolantes, atmósferas hipnóticas y texturas glitch-driven; la pasión por sonidos dark, groovy y psicodélicos construye viajes inmersivos que arrastran al oyente a las sombras del ritmo y la resonancia. Forma parte de la familia Padang Records. Booking: akudamamusicc@gmail.com.',
      de: '<b>James Toa</b>, Neuseeland. Akudama formt Schatten in Klang — Psytech und Dark Progressive verschmolzen mit industriellen und mechanischen Soundscapes. <b>Dark aural alchemy</b> und Storytelling, verborgen in tonaler Kryptografie: jeder Track ist eine Chiffre. Die Musik fließt durch tiefe rollende Basslines, hypnotische Atmosphären und glitch-getriebene Texturen; die Leidenschaft für dunkle, groovige und psychedelische Klänge baut immersive Reisen, die Hörer in die Schatten von Rhythmus und Resonanz ziehen. Teil der Padang-Records-Familie. Booking: akudamamusicc@gmail.com.',
      fr: '<b>James Toa</b>, Nouvelle-Zélande. Akudama sculpte des ombres en son — psytech et dark progressive fusionnés à des soundscapes industriels et mécaniques. <b>Dark aural alchemy</b> et storytelling cachés dans une cryptographie tonale : chaque morceau est un chiffre. La musique coule à travers des basslines profondes et roulantes, des atmosphères hypnotiques et des textures glitch-driven ; la passion pour le sombre, le groovy et le psychédélique bâtit des voyages immersifs qui tirent l\'auditeur dans les ombres du rythme et de la résonance. Fait partie de la famille Padang Records. Booking : akudamamusicc@gmail.com.',
      ja: '<b>James Toa</b>、ニュージーランド出身。Akudama は影を音へと彫り込む — psytech と dark progressive にインダストリアル／メカニカルなサウンドスケープを融合。<b>Dark aural alchemy</b> と、音のクリプトグラフィに隠されたストーリーテリング：各トラックは一つの暗号。音楽は深く転がるベースライン、催眠的なアトモスフィア、グリッチ駆動のテクスチャを流れる。ダーク、グルーヴィー、サイケデリックなサウンドへの情熱が没入的なジャーニーを構築し、聴き手をリズムと共鳴の影の中へと引き込む。Padang Records ファミリーの一員。Booking: akudamamusicc@gmail.com。'
    },

    "Algia": {
      en: '<b>Tóth Bence</b>, Budapest, Hungary. DJ and producer of <b>Dark Progressive and Techno</b> — dense textures, steady pulse. Released <b>Unstable Orbit</b> on Padang Records and headlined <b>Padang Lab Series EP.17</b> (09/10/2025). Contact: algiatek@gmail.com.',
      es: '<b>Tóth Bence</b>, Budapest, Hungría. DJ y productor de <b>Dark Progressive y Techno</b> — texturas densas, pulso firme. Lanzó <b>Unstable Orbit</b> en Padang Records y protagonizó <b>Padang Lab Series EP.17</b> (09/10/2025). Contacto: algiatek@gmail.com.',
      de: '<b>Tóth Bence</b>, Budapest, Ungarn. DJ und Produzent für <b>Dark Progressive und Techno</b> — dichte Texturen, stetiger Puls. Veröffentlichte <b>Unstable Orbit</b> auf Padang Records und stand im Mittelpunkt der <b>Padang Lab Series EP.17</b> (09.10.2025). Kontakt: algiatek@gmail.com.',
      fr: '<b>Tóth Bence</b>, Budapest, Hongrie. DJ et producteur de <b>Dark Progressive et Techno</b> — textures denses, pulsation ferme. A sorti <b>Unstable Orbit</b> sur Padang Records et a porté la <b>Padang Lab Series EP.17</b> (09/10/2025). Contact : algiatek@gmail.com.',
      ja: '<b>Tóth Bence</b>、ハンガリー・ブダペスト出身。<b>Dark Progressive と Techno</b> の DJ／プロデューサー — 濃密なテクスチャと安定したパルス。Padang Records から <b>Unstable Orbit</b> をリリースし、<b>Padang Lab Series EP.17</b>（2025年10月9日）の中心を担う。連絡先: algiatek@gmail.com。'
    },"Alternative Roots": {
      en: '<b>Ricardo Coelho</b>, Sesimbra, Portugal. Discovered psychedelic music in the dark valleys of Portuguese territory and dove into the scene to the point of organising his own parties and moving behind the DJ booth. His production follows the techniques he developed on his own — heavily inspired by <b>psychedelics, dark trance, tech trance</b> and the experimental music of his youth. Deliberate emphasis on heavy beats, deep basslines and dark atmospheres that transport the listener to unknown dimensions. <b>On Padang Records:</b> <b>Mind Control</b> with Champirolls (10/2024).',
      es: '<b>Ricardo Coelho</b>, Sesimbra, Portugal. Descubrió la música psicodélica en los valles oscuros del territorio portugués y se sumergió en la escena al punto de organizar sus propias fiestas y migrar a la cabina como DJ. Su producción sigue las técnicas que él mismo desarrolló — fuertemente inspiradas en <b>psicodélicos, dark trance, tech trance</b> y la música experimental que escuchaba en la juventud. Énfasis deliberado en beats pesados, basslines profundos y atmósferas oscuras que transportan al oyente a dimensiones desconocidas. <b>En Padang Records:</b> <b>Mind Control</b> con Champirolls (10/2024).',
      de: '<b>Ricardo Coelho</b>, Sesimbra, Portugal. Entdeckte psychedelische Musik in den dunklen Tälern Portugals und tauchte so tief in die Szene ein, dass er eigene Partys organisierte und schließlich selbst auflegte. Seine Produktion folgt selbst entwickelten Techniken — stark inspiriert von <b>Psychedelika, Dark Trance, Tech Trance</b> und der experimentellen Musik seiner Jugend. Bewusste Betonung von schweren Beats, tiefen Basslines und düsteren Atmosphären, die den Hörer in unbekannte Dimensionen tragen. <b>Auf Padang Records:</b> <b>Mind Control</b> mit Champirolls (10/2024).',
      fr: '<b>Ricardo Coelho</b>, Sesimbra, Portugal. A découvert la musique psychédélique dans les vallées sombres du territoire portugais et a plongé dans la scène au point d\'organiser ses propres soirées et de passer derrière les platines. Sa production suit les techniques qu\'il a développées seul — fortement inspirées par les <b>psychédéliques, le dark trance, le tech trance</b> et la musique expérimentale de sa jeunesse. Accent délibéré sur des beats lourds, des basslines profondes et des atmosphères sombres qui transportent l\'auditeur vers des dimensions inconnues. <b>Sur Padang Records :</b> <b>Mind Control</b> avec Champirolls (10/2024).',
      ja: '<b>Ricardo Coelho</b>、ポルトガル・セジンブラ出身。ポルトガルの暗い谷でサイケデリック音楽と出会い、シーンに深く飛び込み、自身のパーティを主催し DJ ブースの後ろへと進んだ。プロダクションは独学で築いた技法に基づく — <b>サイケデリック、ダーク・トランス、テック・トランス</b> と若い頃に聴いた実験音楽から強い影響を受ける。重いビート、深いベースライン、未知の次元へと聴く者を運ぶダークなアトモスフィアに意図的にフォーカス。<b>Padang Records から：</b>Champirolls との <b>Mind Control</b>（2024年10月）。'
    },

    "Anadrome": {
      en: '<b>Connor McLean</b>, Central Coast, Australia — <b>Spinal Collective</b> crew. Under the motto "Sounds of a madman", he delivers gritty psychedelia with edge and organic shake. Debut EP <b>Self Inflicted</b> on Padang Records (18/02/2026) — three tracks (Hollow, Ensnared, System Diagnostics) distilling his dark aesthetic.',
      es: '<b>Connor McLean</b>, Central Coast, Australia — colectivo <b>Spinal Collective</b>. Bajo el lema "Sounds of a madman", entrega psicodelia áspera con filo y vibración orgánica. EP debut <b>Self Inflicted</b> en Padang Records (18/02/2026) — tres tracks (Hollow, Ensnared, System Diagnostics) que destilan su estética oscura.',
      de: '<b>Connor McLean</b>, Central Coast, Australien — Kollektiv <b>Spinal Collective</b>. Unter dem Motto "Sounds of a madman" liefert er rauhe Psychedelia mit Kante und organischer Schwingung. Debüt-EP <b>Self Inflicted</b> auf Padang Records (18.02.2026) — drei Tracks (Hollow, Ensnared, System Diagnostics), die seine düstere Ästhetik destillieren.',
      fr: '<b>Connor McLean</b>, Central Coast, Australie — collectif <b>Spinal Collective</b>. Sous la devise "Sounds of a madman", il livre une psychédélie râpeuse au tranchant organique. EP de début <b>Self Inflicted</b> sur Padang Records (18/02/2026) — trois morceaux (Hollow, Ensnared, System Diagnostics) qui distillent son esthétique sombre.',
      ja: '<b>Connor McLean</b>、オーストラリア・セントラルコースト出身 — コレクティブ <b>Spinal Collective</b> 所属。「Sounds of a madman」というモットーのもと、エッジとオーガニックな振動を持つザラついたサイケデリアを届ける。Padang Records からデビュー EP <b>Self Inflicted</b>（2026年2月18日） — 3 トラック（Hollow、Ensnared、System Diagnostics）が彼のダークな美学を凝縮。'
    },"Anaïs Lin": {
      en: 'A striking presence in the Portuguese underground <b>since 2012</b>, expanding beyond borders in the years that followed — her art took her to some of the world\'s biggest festivals: <b>Burning Man</b>, <b>Modem Festival</b> (Croatia), <b>Boom Festival</b> (Portugal), <b>Esoteric Festival</b>, Fora de Tempo Festival and GemFest. Signed to Padang Records in <b>2018</b> and curated <b>TechnoMad</b> — the label\'s most successful compilation to date — and headlined <b>Padang Lab Series EP.11</b>. After crossing multiple continents, planes and stories, she now arrives with something raw, focused and uncompromising. Maintains the experimental alter-ego <b>Inthelinbo</b> (evolved from experiences in the depths of the Australian bush — fast rhythms meeting ethereal atmospheres) and the more intimate side <b>Deepinthelin</b>, where the beat breaks, the subconscious twists and reflection is demanded.',
      es: 'Presencia marcante en la escena underground portuguesa <b>desde 2012</b>, expandiéndose más allá de las fronteras en los años siguientes — su arte la llevó a algunos de los mayores festivales del mundo: <b>Burning Man</b>, <b>Modem Festival</b> (Croacia), <b>Boom Festival</b> (Portugal), <b>Esoteric Festival</b>, Fora de Tempo Festival y GemFest. Firmó con Padang Records en <b>2018</b> y curó <b>TechnoMad</b> — la compilación más exitosa del sello hasta hoy — además de protagonizar la <b>Padang Lab Series EP.11</b>. Tras cruzar múltiples continentes, planos e historias, llega ahora con algo crudo, dirigido y sin concesiones. Mantiene el alter-ego experimental <b>Inthelinbo</b> (evolucionado de experiencias en las profundidades del bush australiano — ritmos rápidos encuentran atmósferas etéreas) y el lado más íntimo <b>Deepinthelin</b>, donde el beat se quiebra, el subconsciente se retuerce y la reflexión es exigida.',
      de: 'Markante Präsenz in der portugiesischen Underground-Szene <b>seit 2012</b>, in den Folgejahren über Grenzen hinaus expandierend — ihre Kunst führte sie zu einigen der größten Festivals der Welt: <b>Burning Man</b>, <b>Modem Festival</b> (Kroatien), <b>Boom Festival</b> (Portugal), <b>Esoteric Festival</b>, Fora de Tempo Festival und GemFest. <b>2018</b> bei Padang Records unter Vertrag, kuratierte sie <b>TechnoMad</b> — bislang die erfolgreichste Compilation des Labels — und stand im Zentrum der <b>Padang Lab Series EP.11</b>. Nach Reisen durch Kontinente, Ebenen und Geschichten kommt sie jetzt mit etwas Rohem, Fokussiertem und Kompromisslosem. Pflegt das experimentelle Alter Ego <b>Inthelinbo</b> (gewachsen aus Erfahrungen in den Tiefen des australischen Bush — schnelle Rhythmen treffen ätherische Atmosphären) sowie die intimere Seite <b>Deepinthelin</b>, wo der Beat bricht, das Unterbewusste sich windet und Reflexion gefordert ist.',
      fr: 'Présence marquante dans la scène underground portugaise <b>depuis 2012</b>, s\'étendant au-delà des frontières dans les années suivantes — son art l\'a portée vers certains des plus grands festivals du monde : <b>Burning Man</b>, <b>Modem Festival</b> (Croatie), <b>Boom Festival</b> (Portugal), <b>Esoteric Festival</b>, Fora de Tempo Festival et GemFest. Signée chez Padang Records en <b>2018</b>, elle a curaté <b>TechnoMad</b> — la compilation la plus aboutie du label à ce jour — et a porté la <b>Padang Lab Series EP.11</b>. Après avoir traversé continents, plans et histoires, elle revient avec quelque chose de brut, dirigé et sans concession. Maintient l\'alter-ego expérimental <b>Inthelinbo</b> (issu d\'expériences au fond du bush australien — rythmes rapides à la rencontre d\'atmosphères éthérées) et le versant plus intime <b>Deepinthelin</b>, où le beat se brise, le subconscient se tord et la réflexion s\'impose.',
      ja: '<b>2012年</b>からポルトガルのアンダーグラウンドシーンの中核として強い存在感を放ち、その後数年で国境を越えて拡大 — そのアートは世界最大級のフェスへと彼女を導いた：<b>Burning Man</b>、<b>Modem Festival</b>（クロアチア）、<b>Boom Festival</b>（ポルトガル）、<b>Esoteric Festival</b>、Fora de Tempo Festival、GemFest。<b>2018年</b>に Padang Records と契約し、<b>TechnoMad</b>（レーベル史上もっとも成功したコンピレーション）をキュレーション、<b>Padang Lab Series EP.11</b> も牽引。複数の大陸、次元、物語を渡り歩いたのち、今、生々しく、的を射た、妥協のない何かを携えて到着する。実験的な別名義 <b>Inthelinbo</b>（オーストラリアの奥地での体験から育まれた — 高速なリズムが幽玄なアトモスフィアと出会う）と、より親密な側面 <b>Deepinthelin</b>（ビートが割れ、潜在意識が捻れ、内省を強いる）も継続。'
    },

    "Backendorf": {
      en: '<b>Camila Backendorf</b>, DJ/producer from Porto Alegre. Part of the Padang Records family, she navigates psytech and dark progressive with clinical sound design and a selection tuned to the dancefloor\\\'s nuances.',
      es: '<b>Camila Backendorf</b>, DJ/productora de Porto Alegre. Forma parte de la familia Padang Records, navegando entre psytech y dark progressive con diseño sonoro clínico y selección atenta a los matices del dancefloor.',
      de: '<b>Camila Backendorf</b>, DJ/Produzentin aus Porto Alegre. Teil der Padang-Records-Familie, bewegt sie sich zwischen Psytech und Dark Progressive mit klinischem Sound-Design und einer Auswahl, die auf die Nuancen des Dancefloors abgestimmt ist.',
      fr: '<b>Camila Backendorf</b>, DJ/productrice de Porto Alegre. Membre de la famille Padang Records, elle navigue entre psytech et dark progressive avec un sound design clinique et une sélection attentive aux nuances du dancefloor.',
      ja: '<b>Camila Backendorf</b>、ブラジル・ポルト・アレグレ出身の DJ／プロデューサー。Padang Records ファミリーの一員として、クリニカルなサウンド・デザインとダンスフロアのニュアンスに敏感なセレクションで、Psytech と Dark Progressive の間を巡る。'
    },"Bensaid": {
      en: '<b>Benjamin Garrido Diaz</b>, Chilean based between Chile and Germany (Hamburg). Musical journey began in <b>2009</b> with the hip-hop project Benproject — collaborations on electronic beats, EPs and live shows built a solid foundation for his approach to rhythm, structure and sound design, forging a strong connection with the energy of live performance. In <b>2012</b> he stepped into the world of DJing, expanding from hip-hop into electronics; his sound evolved organically from glitch hop into minimal techno with a touch of psy, finding a home in <b>dark progressive</b> — where hypnotic grooves, textured atmospheres and emotional depth converge. <b>Defining moment in 2014:</b> a year in Melbourne, Australia — immersed in a vibrant underground scene, festivals, clubs, international connections and a full embrace of the dark progressive movement; it was there that he began producing, developing a sonic identity rooted in deep rhythms and immersive soundscapes. Since 2016 he releases regularly on respected labels including Padang Records. Creative sets between <b>128-140 BPM</b>, master of fluid transitions. <b>On Padang Records:</b> <b>Virtuous Spiral</b> (07/2023), the <b>Slippery Slope</b> remix (Akari System), <b>Onduwave</b> (VA Exogenesis) and <b>Hit for The Hater</b> (Technomad II). Also active as the Voqui project.',
      es: '<b>Benjamin Garrido Diaz</b>, chileno radicado entre Chile y Alemania (Hamburgo). Su viaje musical comenzó en <b>2009</b> con el proyecto hip-hop Benproject — colaboraciones en beats electrónicos, EPs y shows en vivo construyeron una base sólida para su abordaje del ritmo, la estructura y el sound design, forjando una conexión fuerte con la energía de la performance en vivo. En <b>2012</b> entró al mundo del DJing, expandiéndose del hip-hop a la electrónica; su sonido evolucionó orgánicamente del glitch hop al minimal techno con pitada de psy, encontrando casa en el <b>dark progressive</b> — espacio donde grooves hipnóticos, atmósferas texturadas y profundidad emocional convergen. <b>Defining moment en 2014:</b> un año en Melbourne, Australia — inmerso en una vibrante escena underground, festivales, clubs, conexiones internacionales y un abrazo pleno al movimiento dark progressive; fue allí donde comenzó a producir, desarrollando una identidad sónica enraizada en ritmos profundos y soundscapes inmersivos. Desde 2016 lanza regularmente en sellos respetados, incluida Padang Records. Sets creativos entre <b>128-140 BPM</b>, maestro en transiciones fluidas. <b>En Padang Records:</b> <b>Virtuous Spiral</b> (07/2023), remix <b>Slippery Slope</b> (Akari System), <b>Onduwave</b> (VA Exogenesis), <b>Hit for The Hater</b> (Technomad II). También activo como proyecto Voqui.',
      de: '<b>Benjamin Garrido Diaz</b>, Chilene mit Lebensmittelpunkt zwischen Chile und Deutschland (Hamburg). Die musikalische Reise begann <b>2009</b> mit dem Hip-Hop-Projekt Benproject — Kollaborationen an elektronischen Beats, EPs und Live-Shows legten eine solide Grundlage für seinen Umgang mit Rhythmus, Struktur und Sound Design und schmiedeten eine starke Verbindung zur Energie der Live-Performance. <b>2012</b> trat er in die DJ-Welt ein und erweiterte sich vom Hip-Hop in die Elektronik; sein Sound entwickelte sich organisch vom Glitch Hop hin zu Minimal Techno mit einem Touch Psy und fand seine Heimat im <b>Dark Progressive</b> — wo hypnotische Grooves, texturierte Atmosphären und emotionale Tiefe zusammenfließen. <b>Schlüsselmoment 2014:</b> ein Jahr in Melbourne, Australien — eingetaucht in eine lebendige Underground-Szene, Festivals, Clubs, internationale Verbindungen und die volle Umarmung der Dark-Progressive-Bewegung; dort begann er zu produzieren und entwickelte eine klangliche Identität, die in tiefen Rhythmen und immersiven Soundscapes verwurzelt ist. Seit 2016 veröffentlicht er regelmäßig auf renommierten Labels, darunter Padang Records. Kreative Sets zwischen <b>128-140 BPM</b>, Meister fließender Übergänge. <b>Auf Padang Records:</b> <b>Virtuous Spiral</b> (07/2023), Remix <b>Slippery Slope</b> (Akari System), <b>Onduwave</b> (VA Exogenesis), <b>Hit for The Hater</b> (Technomad II). Ebenfalls aktiv als Projekt Voqui.',
      fr: '<b>Benjamin Garrido Diaz</b>, Chilien partagé entre le Chili et l\'Allemagne (Hambourg). Le parcours musical a démarré en <b>2009</b> avec le projet hip-hop Benproject — des collaborations sur beats électroniques, EPs et concerts ont posé une base solide pour son approche du rythme, de la structure et du sound design, forgeant un lien fort avec l\'énergie de la scène. En <b>2012</b>, il entre dans le monde du DJing en élargissant son champ du hip-hop à l\'électronique ; son son évolue organiquement du glitch hop vers le minimal techno teinté de psy, trouvant refuge dans le <b>dark progressive</b> — espace où grooves hypnotiques, atmosphères texturées et profondeur émotionnelle convergent. <b>Moment fondateur en 2014 :</b> une année à Melbourne, Australie — immergé dans une scène underground vibrante, festivals, clubs, connexions internationales et pleine adhésion au mouvement dark progressive ; c\'est là qu\'il commence à produire, développant une identité sonore enracinée dans des rythmes profonds et des soundscapes immersifs. Depuis 2016, il sort régulièrement sur des labels respectés, dont Padang Records. Sets créatifs entre <b>128 et 140 BPM</b>, maître des transitions fluides. <b>Sur Padang Records :</b> <b>Virtuous Spiral</b> (07/2023), remix <b>Slippery Slope</b> (Akari System), <b>Onduwave</b> (VA Exogenesis), <b>Hit for The Hater</b> (Technomad II). Également actif sous le projet Voqui.',
      ja: '<b>Benjamin Garrido Diaz</b>、チリ人で、チリとドイツ（ハンブルク）の間を拠点とする。音楽の旅は <b>2009年</b>、ヒップホップ・プロジェクト Benproject から始まった — エレクトロニックなビート、EP、ライブショーでのコラボレーションがリズム、構造、サウンドデザインへのアプローチの強固な基盤となり、ライブ・パフォーマンスのエネルギーとの強い結びつきを鍛えた。<b>2012年</b>に DJ の世界へ入り、ヒップホップからエレクトロニクスへと範囲を広げ、サウンドは glitch hop から minimal techno with a touch of psy へと有機的に進化、催眠的なグルーヴ、テクスチャあるアトモスフィア、感情的な深みが交差する <b>dark progressive</b> に居場所を見出した。<b>2014年の決定的な瞬間：</b>オーストラリア・メルボルンでの1年間 — 活気あるアンダーグラウンドシーン、フェス、クラブ、国際的なつながり、そして dark progressive ムーブメントへの完全な没入。そこで制作を始め、深いリズムと没入的なサウンドスケープに根ざした音のアイデンティティを築いた。2016年から Padang Records をはじめとする評価あるレーベルでコンスタントにリリース。<b>128-140 BPM</b> のクリエイティブなセット、流麗なトランジションの名手。<b>Padang Records から：</b><b>Virtuous Spiral</b>（2023年7月）、<b>Slippery Slope</b>（Akari System）リミックス、<b>Onduwave</b>（VA Exogenesis）、<b>Hit for The Hater</b>（Technomad II）。Voqui プロジェクトとしても活動。'
    },"Black11": {
      en: '<b>Black11 Frequency</b>, artist from India. Connected to Padang Records through psychedelic frequency. Present on <a href="https://www.instagram.com/black11_frequency/" target="_blank" rel="noopener" style="color:var(--neon-1)">Instagram</a>.',
      es: '<b>Black11 Frequency</b>, artista de la India. Conectado a Padang Records por la frecuencia psicodélica. Presente en <a href="https://www.instagram.com/black11_frequency/" target="_blank" rel="noopener" style="color:var(--neon-1)">Instagram</a>.',
      de: '<b>Black11 Frequency</b>, Künstler aus Indien. Mit Padang Records über die psychedelische Frequenz verbunden. Auf <a href="https://www.instagram.com/black11_frequency/" target="_blank" rel="noopener" style="color:var(--neon-1)">Instagram</a>.',
      fr: '<b>Black11 Frequency</b>, artiste indien. Lié à Padang Records par la fréquence psychédélique. Présent sur <a href="https://www.instagram.com/black11_frequency/" target="_blank" rel="noopener" style="color:var(--neon-1)">Instagram</a>.',
      ja: '<b>Black11 Frequency</b>、インドのアーティスト。サイケデリックな周波数を介して Padang Records と繋がる。<a href="https://www.instagram.com/black11_frequency/" target="_blank" rel="noopener" style="color:var(--neon-1)">Instagram</a> で活動中。'
    },

    "Camps Elisis": {
      en: '<b>Alejandro Camps</b>, born in Mexico City and raised on the southern coast. Started at 12 on guitar and drums; today he crafts immersive soundscapes with deep atmospheric textures. On Padang Records: <b>Quantum Waves</b> (08/2019), <b>The Deserted Forest</b> (08/2025) and <b>Dimension</b>. Delivered <b>Padang Lab Series EP.8</b> as a live set.',
      es: '<b>Alejandro Camps</b>, nacido en Ciudad de México y criado en la costa sur. Empezó a los 12 con guitarra y batería; hoy crea soundscapes inmersivos con texturas atmosféricas profundas. En Padang Records: <b>Quantum Waves</b> (08/2019), <b>The Deserted Forest</b> (08/2025) y <b>Dimension</b>. Presentó <b>Padang Lab Series EP.8</b> en live set.',
      de: '<b>Alejandro Camps</b>, geboren in Mexiko-Stadt, aufgewachsen an der Südküste. Begann mit 12 an Gitarre und Schlagzeug; heute formt er immersive Soundscapes mit tiefen atmosphärischen Texturen. Auf Padang Records: <b>Quantum Waves</b> (08/2019), <b>The Deserted Forest</b> (08/2025) und <b>Dimension</b>. Lieferte <b>Padang Lab Series EP.8</b> als Live-Set.',
      fr: '<b>Alejandro Camps</b>, né à Mexico et élevé sur la côte sud. A commencé à 12 ans à la guitare et à la batterie; aujourd\\\'hui il façonne des soundscapes immersifs aux textures atmosphériques profondes. Sur Padang Records : <b>Quantum Waves</b> (08/2019), <b>The Deserted Forest</b> (08/2025) et <b>Dimension</b>. A livré <b>Padang Lab Series EP.8</b> en live set.',
      ja: '<b>Alejandro Camps</b>、メキシコシティ生まれ、南海岸育ち。12歳でギターとドラムを始め、今では深いアトモスフェリックなテクスチャを持つ没入型サウンドスケープを構築。Padang Records からは <b>Quantum Waves</b>（2019年8月）、<b>The Deserted Forest</b>（2025年8月）、<b>Dimension</b> をリリース。<b>Padang Lab Series EP.8</b> をライブセットで披露。'
    },"Champirolls": {
      en: '<b>Julien Poujol</b>, Toulouse, France. Immersed in Psytrance production for more than <b>10 years</b>, Champirolls has built a Dark Progressive identity marked by rolling basslines, deep grooves and hypnotic intensity without ornament. Also involved in the local scene through <b>ChronoZone</b> and <b>Bonne Mine Chaï Shop</b>, contributing stage management and artistic installations — building the vibe with joy well beyond the booth. Released on Padang Records and headlined <b>Padang Lab Series EP.20</b> (19/12/2025). The last two years lifted the project to major stages: <b>Boom Festival</b> (Alchemy Circle, 2025), <b>Hadra</b> (Main Stage, 2025), <b>Bucht Der Träumer</b> (Waltdraut stage, 2024), Nataraja, and a string of other festivals. Contact: champirollsmusic@gmail.com.',
      es: '<b>Julien Poujol</b>, Toulouse, Francia. Inmerso en la producción Psytrance hace más de <b>10 años</b>, Champirolls ha construido una identidad Dark Progressive marcada por basslines rolantes, grooves profundos e intensidad hipnótica sin ornamento. También involucrado en la escena local vía <b>ChronoZone</b> y <b>Bonne Mine Chaï Shop</b>, contribuyendo con stage management e instalaciones artísticas — construyendo la vibe con alegría más allá de la cabina. Lanzó en Padang Records y protagonizó <b>Padang Lab Series EP.20</b> (19/12/2025). Los últimos dos años elevaron el proyecto a escenarios mayores: <b>Boom Festival</b> (Alchemy Circle, 2025), <b>Hadra</b> (Main Stage, 2025), <b>Bucht Der Träumer</b> (Waltdraut stage, 2024), Nataraja, y una secuencia de otros festivales. Contacto: champirollsmusic@gmail.com.',
      de: '<b>Julien Poujol</b>, Toulouse, Frankreich. Seit über <b>10 Jahren</b> in der Psytrance-Produktion verwurzelt, hat Champirolls eine Dark-Progressive-Identität aufgebaut, geprägt von rollenden Basslines, tiefen Grooves und schmuckloser hypnotischer Intensität. Auch in der lokalen Szene aktiv über <b>ChronoZone</b> und <b>Bonne Mine Chaï Shop</b>, wo er Stagemanagement und künstlerische Installationen beisteuert — und so weit über die Booth hinaus mit Freude zur Vibe beiträgt. Veröffentlicht auf Padang Records und Mittelpunkt der <b>Padang Lab Series EP.20</b> (19.12.2025). Die letzten zwei Jahre brachten das Projekt auf große Bühnen: <b>Boom Festival</b> (Alchemy Circle, 2025), <b>Hadra</b> (Main Stage, 2025), <b>Bucht Der Träumer</b> (Waltdraut Stage, 2024), Nataraja und eine Reihe weiterer Festivals. Kontakt: champirollsmusic@gmail.com.',
      fr: '<b>Julien Poujol</b>, Toulouse, France. Plongé dans la production Psytrance depuis plus de <b>10 ans</b>, Champirolls a forgé une identité Dark Progressive marquée par des basslines roulantes, des grooves profonds et une intensité hypnotique sans fioriture. Également engagé dans la scène locale via <b>ChronoZone</b> et <b>Bonne Mine Chaï Shop</b>, où il s\'occupe de stage management et d\'installations artistiques — construisant la vibe avec joie bien au-delà de la cabine. Sorti sur Padang Records et a porté la <b>Padang Lab Series EP.20</b> (19/12/2025). Les deux dernières années ont propulsé le projet sur de grandes scènes : <b>Boom Festival</b> (Alchemy Circle, 2025), <b>Hadra</b> (Main Stage, 2025), <b>Bucht Der Träumer</b> (scène Waltdraut, 2024), Nataraja et une série d\'autres festivals. Contact : champirollsmusic@gmail.com.',
      ja: '<b>Julien Poujol</b>、フランス・トゥールーズ出身。<b>10年以上</b>にわたり Psytrance プロダクションに没頭し、Champirolls は転がるベースライン、深いグルーヴ、装飾を排した催眠的な強度に特徴づけられる Dark Progressive のアイデンティティを築いてきた。<b>ChronoZone</b> や <b>Bonne Mine Chaï Shop</b> を通じてローカルシーンにも関わり、ステージ・マネジメントやアート・インスタレーションを担当 — ブースの外で喜びとともに場の空気を作り上げる。Padang Records からリリースし、<b>Padang Lab Series EP.20</b>（2025年12月19日）を牽引。この2年でプロジェクトは主要ステージへと飛躍した：<b>Boom Festival</b>（Alchemy Circle、2025）、<b>Hadra</b>（Main Stage、2025）、<b>Bucht Der Träumer</b>（Waltdraut stage、2024）、Nataraja、そしてその他多数のフェス。連絡先: champirollsmusic@gmail.com。'
    },

    "Dienstmann": {
      en: '<b>Carlos Dienstmann</b>, Novo Hamburgo (BR). <b>Founder and curator of Padang Records</b> — "two decades shaping underground music, events, and artist curatorship". Style: minimalist psychedelia dominated by strong techno influences. <b>On Padang Records:</b> <b>Circuit Breakdown EP</b> (20/10/2021) — 4 tracks (Data Railway, Circuit Breakdown, No Duality, The Proxy 2 with Vorg); <b>Aka Brujo</b> (03/2022); <b>Offline Providings</b> (03/2022); collaboration <b>Fractal Dimensions</b> (Dienstmann vs Vorg). Delivered <b>Padang Lab Series EP.10</b> as a live set. The vision and artistic direction behind every Padang release.',
      es: '<b>Carlos Dienstmann</b>, Novo Hamburgo (BR). <b>Fundador y curador de Padang Records</b> — "two decades shaping underground music, events, and artist curatorship". Estilo: psicodelia minimalista dominada por fuertes influencias techno. <b>En Padang Records:</b> <b>Circuit Breakdown EP</b> (20/10/2021) — 4 tracks (Data Railway, Circuit Breakdown, No Duality, The Proxy 2 con Vorg); <b>Aka Brujo</b> (03/2022); <b>Offline Providings</b> (03/2022); colaboración <b>Fractal Dimensions</b> (Dienstmann vs Vorg). Presentó <b>Padang Lab Series EP.10</b> en live set. Visión y dirección artística detrás de toda la discografía Padang.',
      de: '<b>Carlos Dienstmann</b>, Novo Hamburgo (BR). <b>Gründer und Kurator von Padang Records</b> — "two decades shaping underground music, events, and artist curatorship". Stil: minimalistische Psychedelia, geprägt von starken Techno-Einflüssen. <b>Auf Padang Records:</b> <b>Circuit Breakdown EP</b> (20.10.2021) — 4 Tracks (Data Railway, Circuit Breakdown, No Duality, The Proxy 2 mit Vorg); <b>Aka Brujo</b> (03/2022); <b>Offline Providings</b> (03/2022); Kollaboration <b>Fractal Dimensions</b> (Dienstmann vs Vorg). Lieferte <b>Padang Lab Series EP.10</b> als Live-Set. Vision und künstlerische Leitung hinter jeder Padang-Veröffentlichung.',
      fr: '<b>Carlos Dienstmann</b>, Novo Hamburgo (BR). <b>Fondateur et curateur de Padang Records</b> — « two decades shaping underground music, events, and artist curatorship ». Style : psychédélie minimaliste dominée par de fortes influences techno. <b>Sur Padang Records :</b> <b>Circuit Breakdown EP</b> (20/10/2021) — 4 morceaux (Data Railway, Circuit Breakdown, No Duality, The Proxy 2 avec Vorg); <b>Aka Brujo</b> (03/2022); <b>Offline Providings</b> (03/2022); collaboration <b>Fractal Dimensions</b> (Dienstmann vs Vorg). A livré <b>Padang Lab Series EP.10</b> en live set. Vision et direction artistique derrière chaque sortie Padang.',
      ja: '<b>Carlos Dienstmann</b>、ブラジル・ノヴォ・アンブルゴ出身。<b>Padang Records の創設者兼キュレーター</b> — 「two decades shaping underground music, events, and artist curatorship」（アンダーグラウンド音楽・イベント・アーティスト・キュレーションを 20 年にわたって形作る）。スタイル：強いテクノの影響に支配された、ミニマリスティックなサイケデリア。<b>Padang Records から：</b><b>Circuit Breakdown EP</b>（2021年10月20日） — 4トラック（Data Railway、Circuit Breakdown、No Duality、Vorg との The Proxy 2）；<b>Aka Brujo</b>（2022年3月）；<b>Offline Providings</b>（2022年3月）；コラボ <b>Fractal Dimensions</b>（Dienstmann vs Vorg）。<b>Padang Lab Series EP.10</b> をライブセットで披露。Padang のすべてのリリースを貫くビジョンとアーティスティック・ディレクション。'
    },"Diorama": {
      en: '<b>Nikhil Harpalani</b>, Dubai / India. Recognized for the signature <b>bouncy dark progressive</b> blend of Padang Records — a sound that evolved across several label compilations, showing deep musical sensibilities. <b>DJ since 2015</b>, performed across the Middle East and various regions of India, building a reputation for immersive and energetic sets. A devoted psychedelic music enthusiast <b>since the late 1990s</b> — two decades curating and collecting intelligent, forward-thinking sounds. His journey reflects a deep-rooted passion for the genre, shaping a distinctive style that resonates with listeners both on and off the dance floor. <b>Side project:</b> <b>Helter Skelter</b> — psytrance alias for mind-twisting atmospheric forest sets.',
      es: '<b>Nikhil Harpalani</b>, Dubái / India. Reconocido por el blend signature de <b>bouncy dark progressive</b> de Padang Records — un sonido que evolucionó a través de varias compilaciones del sello, mostrando sensibilidades musicales profundas. <b>DJ desde 2015</b>, ha actuado en Oriente Medio y diversas regiones de la India, construyendo reputación por sets inmersivos y energéticos. Entusiasta devoto de la música psicodélica <b>desde finales de los 1990</b> — dos décadas curando y coleccionando sonidos inteligentes y forward-thinking. Su trayectoria refleja una pasión enraizada por el género, moldeando un estilo distintivo que resuena dentro y fuera de la pista. <b>Side project:</b> <b>Helter Skelter</b> — alias psytrance para sets de forest atmosférico y mind-twisting.',
      de: '<b>Nikhil Harpalani</b>, Dubai / Indien. Bekannt für die Signature-Mischung von <b>bouncy dark progressive</b> von Padang Records — ein Sound, der sich über mehrere Label-Compilations entwickelt hat und tiefe musikalische Sensibilität zeigt. <b>DJ seit 2015</b>, hat im Nahen Osten und in verschiedenen Regionen Indiens aufgelegt und sich einen Ruf für immersive und energiegeladene Sets aufgebaut. Hingebungsvoller Psychedelic-Enthusiast <b>seit Ende der 1990er</b> — zwei Jahrzehnte des Kuratierens und Sammelns intelligenter, vorwärtsdenkender Sounds. Sein Weg spiegelt eine tief verwurzelte Leidenschaft für das Genre wider und prägt einen unverwechselbaren Stil, der die Hörer auf und neben dem Dancefloor erreicht. <b>Side Project:</b> <b>Helter Skelter</b> — Psytrance-Alias für mind-twisting atmosphärische Forest-Sets.',
      fr: '<b>Nikhil Harpalani</b>, Dubaï / Inde. Reconnu pour le blend signature de <b>bouncy dark progressive</b> de Padang Records — un son qui a évolué à travers plusieurs compilations du label, montrant des sensibilités musicales profondes. <b>DJ depuis 2015</b>, s\'est produit au Moyen-Orient et dans diverses régions de l\'Inde, bâtissant une réputation pour des sets immersifs et énergiques. Passionné dévoué de musique psychédélique <b>depuis la fin des années 1990</b> — deux décennies à curater et collectionner des sons intelligents et avant-gardistes. Son parcours reflète une passion enracinée pour le genre, façonnant un style distinctif qui résonne avec les auditeurs sur et hors de la piste. <b>Side project :</b> <b>Helter Skelter</b> — alias psytrance pour des sets forest atmosphériques et mind-twisting.',
      ja: '<b>Nikhil Harpalani</b>、ドバイ／インド。Padang Records の <b>バウンシーなダーク・プログレッシブ</b>シグネチャー・ブレンドで知られる — レーベルの複数のコンピレーションを通じて進化したサウンドが、深い音楽的感性を示す。<b>2015 年から DJ</b>として中東とインド各地で演奏、没入感あるエネルギッシュなセットで評判を築く。<b>1990 年代後半から</b>サイケデリック音楽に没頭してきた愛好家 — 20 年間にわたり知的で先進的なサウンドをキュレーション、コレクション。ジャンルへの深い情熱が独自のスタイルを形作り、フロアの内外でリスナーに響く。<b>サイドプロジェクト：</b><b>Helter Skelter</b> — マインドツイスティングな雰囲気の Forest セット用 psytrance エイリアス。'
    },

    "Fevered Shiva": {
      en: 'Berlin-based, originally from Australia. "Described by his neighbours as definitely not a musician" — his music is full of creak, growl and rumble that summon curious bunyips to the dancefloor. Releases on Padang Records: <b>Inside Out</b>, <b>Klaranoia</b>, <b>Scattered Pattern</b>, <b>Bug\\\'s Life</b> and <b>Sanskritzophrenia</b>. Released an album with Version Bizar in 08/2018.',
      es: 'Radicado en Berlín, originalmente de Australia. "Described by his neighbours as definitely not a musician" — su música está llena de creak, growl y rumble que invocan bunyips curiosos al dancefloor. Releases en Padang Records: <b>Inside Out</b>, <b>Klaranoia</b>, <b>Scattered Pattern</b>, <b>Bug\\\'s Life</b> y <b>Sanskritzophrenia</b>. Lanzó un álbum con Version Bizar en 08/2018.',
      de: 'In Berlin ansässig, ursprünglich aus Australien. "Described by his neighbours as definitely not a musician" — seine Musik ist voll von Knarren, Knurren und Rumpeln, die neugierige Bunyips auf die Tanzfläche locken. Releases auf Padang Records: <b>Inside Out</b>, <b>Klaranoia</b>, <b>Scattered Pattern</b>, <b>Bug\\\'s Life</b> und <b>Sanskritzophrenia</b>. Album mit Version Bizar im 08/2018.',
      fr: 'Basé à Berlin, originaire d\\\'Australie. « Described by his neighbours as definitely not a musician » — sa musique est pleine de craquements, de grognements et de grondements qui attirent les bunyips curieux sur la piste. Sorties chez Padang Records : <b>Inside Out</b>, <b>Klaranoia</b>, <b>Scattered Pattern</b>, <b>Bug\\\'s Life</b> et <b>Sanskritzophrenia</b>. Album avec Version Bizar en 08/2018.',
      ja: 'ベルリン拠点、オーストラリア出身。「Described by his neighbours as definitely not a musician」 — 軋み、唸り、轟きに満ちた彼の音楽は、好奇心旺盛な bunyips をダンスフロアへ呼び寄せる。Padang Records からのリリース：<b>Inside Out</b>、<b>Klaranoia</b>、<b>Scattered Pattern</b>、<b>Bug\\\'s Life</b>、<b>Sanskritzophrenia</b>。2018年8月に Version Bizar とアルバムをリリース。'
    },

    "Green Waves": {
      en: '<b>Artur Vilela</b>, Belo Horizonte / Ouro Branco-MG. Started on drums at 12, inspired by his father (a rock DJ in the 80s-90s); at 14 he discovered electronic music and moved into DJing and production. Dynamic style: a fusion of <b>groove and introspection</b>, with <b>Psy Trance</b> elements and a focus on sound design. On Padang Records: <b>Surfing in Oscillations</b> (05/2023, 3 tracks) and <b>Chronicles</b> (10/2025, 10 tracks — <i>sub-bass that walks, percussion that thinks</i>). Collaborations: <b>Bon Voyage</b> with Slip Hypnotic, <b>Digital to Reality</b> with Inverted World.',
      es: '<b>Artur Vilela</b>, Belo Horizonte / Ouro Branco-MG. Empezó tocando batería a los 12, inspirado por su padre (DJ de rock en los 80-90); a los 14 descubrió la música electrónica y se dedicó al DJing y la producción. Estilo dinámico: fusión de <b>groove e introspección</b>, con elementos de <b>Psy Trance</b> y foco en el sound design. En Padang Records: <b>Surfing in Oscillations</b> (05/2023, 3 tracks) y <b>Chronicles</b> (10/2025, 10 tracks — <i>sub-bass que camina, percusión que piensa</i>). Colaboraciones: <b>Bon Voyage</b> con Slip Hypnotic, <b>Digital to Reality</b> con Inverted World.',
      de: '<b>Artur Vilela</b>, Belo Horizonte / Ouro Branco-MG. Begann mit 12 am Schlagzeug, inspiriert von seinem Vater (Rock-DJ in den 80er-90er Jahren); mit 14 entdeckte er die elektronische Musik und wechselte zu DJing und Produktion. Dynamischer Stil: Fusion aus <b>Groove und Introspektion</b>, mit <b>Psy-Trance</b>-Elementen und Fokus auf Sound Design. Auf Padang Records: <b>Surfing in Oscillations</b> (05/2023, 3 Tracks) und <b>Chronicles</b> (10/2025, 10 Tracks — <i>Sub-Bass der schreitet, Percussion die denkt</i>). Kollaborationen: <b>Bon Voyage</b> mit Slip Hypnotic, <b>Digital to Reality</b> mit Inverted World.',
      fr: '<b>Artur Vilela</b>, Belo Horizonte / Ouro Branco-MG. A commencé à la batterie à 12 ans, inspiré par son père (DJ rock des années 80-90); à 14 ans, il découvre la musique électronique et se tourne vers le DJing et la production. Style dynamique : fusion de <b>groove et introspection</b>, avec des éléments de <b>Psy Trance</b> et un accent sur le sound design. Sur Padang Records : <b>Surfing in Oscillations</b> (05/2023, 3 morceaux) et <b>Chronicles</b> (10/2025, 10 morceaux — <i>sub-bass qui marche, percussion qui pense</i>). Collaborations : <b>Bon Voyage</b> avec Slip Hypnotic, <b>Digital to Reality</b> avec Inverted World.',
      ja: '<b>Artur Vilela</b>、ブラジル・ベロオリゾンテ／オウロ・ブランコ-MG。12歳でドラムを始め（父親が80-90年代のロック DJ だった影響）、14歳でエレクトロニック音楽に出会い、DJ／プロデューサーへ。ダイナミックな作風：<b>グルーヴと内省</b>の融合、<b>Psy Trance</b> の要素と sound design への注力。Padang Records から：<b>Surfing in Oscillations</b>（2023年5月、3トラック）、<b>Chronicles</b>（2025年10月、10トラック — <i>歩くサブベース、考えるパーカッション</i>）。コラボ：<b>Bon Voyage</b>（Slip Hypnotic）、<b>Digital to Reality</b>（Inverted World）。'
    },"Groovy Smoothy": {
      en: '<b>Arian David Selim Kramer</b>, based between Darmstadt and Frankfurt, Germany. DJ and producer crafting <b>groovy, deep and psychedelic</b> electronic music rooted in <b>Zenonesque, Dark Progressive and Psy Tech</b>. Influences range from techno to psychedelic rock, heavy metal and 70s music — his sound combines organic textures with precise, driven grooves. Playing clubs and festivals <b>since 2016</b>; now part of Padang Records, he is working on his debut EP. <b>On Padang Records:</b> <b>Advent of the Submerged</b> (01/2026). Contact: groovysmoothy.music@gmail.com.',
      es: '<b>Arian David Selim Kramer</b>, basado entre Darmstadt y Frankfurt, Alemania. DJ y productor crafting música electrónica <b>groovy, deep y psychedelic</b> enraizada en <b>Zenonesque, Dark Progressive y Psy Tech</b>. Influencias van del techno al rock psicodélico, heavy metal y música de los años 70 — su sonido combina texturas orgánicas con grooves precisos y dirigidos. Toca en clubes y festivales <b>desde 2016</b>; ahora parte de Padang Records, está trabajando en su debut EP. <b>En Padang Records:</b> <b>Advent of the Submerged</b> (01/2026). Contacto: groovysmoothy.music@gmail.com.',
      de: '<b>Arian David Selim Kramer</b>, zwischen Darmstadt und Frankfurt ansässig, Deutschland. DJ und Produzent, der <b>groovige, tiefe und psychedelische</b> elektronische Musik kreiert, verwurzelt in <b>Zenonesque, Dark Progressive und Psy Tech</b>. Einflüsse reichen von Techno über psychedelischen Rock, Heavy Metal bis hin zu Musik der 70er — sein Sound verbindet organische Texturen mit präzisen, treibenden Grooves. Spielt <b>seit 2016</b> in Clubs und auf Festivals; nun Teil von Padang Records, arbeitet er an seiner Debüt-EP. <b>Auf Padang Records:</b> <b>Advent of the Submerged</b> (01/2026). Kontakt: groovysmoothy.music@gmail.com.',
      fr: '<b>Arian David Selim Kramer</b>, partagé entre Darmstadt et Francfort, Allemagne. DJ et producteur façonnant une musique électronique <b>groovy, deep et psychedelic</b> ancrée dans le <b>Zenonesque, Dark Progressive et Psy Tech</b>. Les influences vont du techno au rock psychédélique, en passant par le heavy metal et la musique des années 70 — son son combine textures organiques et grooves précis et dirigés. Joue en clubs et festivals <b>depuis 2016</b> ; désormais membre de Padang Records, il travaille sur son premier EP. <b>Sur Padang Records :</b> <b>Advent of the Submerged</b> (01/2026). Contact : groovysmoothy.music@gmail.com.',
      ja: '<b>Arian David Selim Kramer</b>、ドイツ・ダルムシュタットとフランクフルトを拠点とする。<b>Zenonesque、Dark Progressive、Psy Tech</b> に根ざした <b>groovy・deep・psychedelic</b> なエレクトロニック・ミュージックを制作する DJ ／プロデューサー。影響源はテクノからサイケデリック・ロック、ヘヴィメタル、70年代の音楽まで — オーガニックなテクスチャと精密で推進力あるグルーヴを融合させたサウンド。<b>2016年から</b>クラブとフェスでプレイ。現在は Padang Records の一員として、デビュー EP を制作中。<b>Padang Records から：</b><b>Advent of the Submerged</b>（2026年1月）。連絡先: groovysmoothy.music@gmail.com。'
    },"Headweller": {
      en: '<b>Christos Chouvardas</b>, born in Thessaloniki, Greece, in <b>1990</b>. In the multidimensional world of electronic music, Christos stands out for his unique ability to craft sounds that blend spiritual evolution with rhythm and movement — composition that fuses spiritual depth with the energy of psy-trance. Delivered the <b>Padang Lab Series EP.1</b>. <b>Festivals:</b> Shankra Festival (Switzerland), Tree Of Life Festival (Turkey), Solstice Festival (Netherlands), Revision Festival (Greece), plus indoor appearances in Greece and abroad. <b>On Padang Records:</b> <b>The Weight of Thought EP</b> (07/2025), <b>The Source Of Fear</b>, <b>Noctura</b> (with Smokcid) and <b>The Cruellest Master</b> (VA Reborn). In <b>2022</b> his love for ambient and slow-evolution music led him to compose for dance-theatre, shorts and art videos. Main goal: to expand musical boundaries through experimentation, contributing to people\'s spiritual evolution — creating states that invite listeners to embark on journeys of transformation, self-knowledge and unity. Contact: headweller_msc@hotmail.com.',
      es: '<b>Christos Chouvardas</b>, nacido en Tesalónica, Grecia, en <b>1990</b>. En el mundo multidimensional de la música electrónica, Christos se destaca por su habilidad única de crear sonidos que mezclan evolución espiritual con ritmo y movimiento — composición que combina profundidad espiritual con la energía del psy-trance. Presentó la <b>Padang Lab Series EP.1</b>. <b>Festivales:</b> Shankra Festival (Suiza), Tree Of Life Festival (Turquía), Solstice Festival (Holanda), Revision Festival (Grecia), además de apariciones indoor en Grecia y el exterior. <b>En Padang Records:</b> <b>The Weight of Thought EP</b> (07/2025), <b>The Source Of Fear</b>, <b>Noctura</b> (con Smokcid) y <b>The Cruellest Master</b> (VA Reborn). En <b>2022</b> su amor por el ambient y la música de evolución lenta lo llevó a componer para dance-theatre, cortos y videos artísticos. Objetivo principal: expandir las fronteras musicales a través de la experimentación, contribuyendo a la evolución espiritual de las personas — creando estados que invitan al oyente a embarcarse en viajes de transformación, autoconocimiento y unidad. Contacto: headweller_msc@hotmail.com.',
      de: '<b>Christos Chouvardas</b>, geboren in Thessaloniki, Griechenland, im Jahr <b>1990</b>. In der multidimensionalen Welt der elektronischen Musik sticht Christos durch seine einzigartige Fähigkeit hervor, Klänge zu schaffen, die spirituelle Evolution mit Rhythmus und Bewegung verbinden — Kompositionen, die spirituelle Tiefe mit der Energie des Psy-Trance vereinen. Lieferte die <b>Padang Lab Series EP.1</b>. <b>Festivals:</b> Shankra Festival (Schweiz), Tree Of Life Festival (Türkei), Solstice Festival (Niederlande), Revision Festival (Griechenland) sowie Indoor-Auftritte in Griechenland und im Ausland. <b>Auf Padang Records:</b> <b>The Weight of Thought EP</b> (07/2025), <b>The Source Of Fear</b>, <b>Noctura</b> (mit Smokcid) und <b>The Cruellest Master</b> (VA Reborn). <b>2022</b> führte ihn seine Liebe zu Ambient und sich langsam entwickelnder Musik dazu, für Tanztheater, Kurzfilme und Kunstvideos zu komponieren. Hauptziel: musikalische Grenzen durch Experimente zu erweitern und zur spirituellen Evolution der Menschen beizutragen — Zustände zu schaffen, die Hörer auf Reisen der Transformation, Selbsterkenntnis und Einheit einladen. Kontakt: headweller_msc@hotmail.com.',
      fr: '<b>Christos Chouvardas</b>, né à Thessalonique, Grèce, en <b>1990</b>. Dans le monde multidimensionnel de la musique électronique, Christos se distingue par sa capacité unique à façonner des sons qui mêlent évolution spirituelle, rythme et mouvement — des compositions où la profondeur spirituelle rencontre l\'énergie du psy-trance. A livré la <b>Padang Lab Series EP.1</b>. <b>Festivals :</b> Shankra Festival (Suisse), Tree Of Life Festival (Turquie), Solstice Festival (Pays-Bas), Revision Festival (Grèce), ainsi que des apparitions indoor en Grèce et à l\'étranger. <b>Sur Padang Records :</b> <b>The Weight of Thought EP</b> (07/2025), <b>The Source Of Fear</b>, <b>Noctura</b> (avec Smokcid) et <b>The Cruellest Master</b> (VA Reborn). En <b>2022</b>, son amour pour l\'ambient et la musique à évolution lente le conduit à composer pour le dance-theatre, le court-métrage et la vidéo artistique. Objectif principal : étendre les frontières musicales par l\'expérimentation, contribuer à l\'évolution spirituelle des gens — créer des états qui invitent l\'auditeur à des voyages de transformation, de connaissance de soi et d\'unité. Contact : headweller_msc@hotmail.com.',
      ja: '<b>Christos Chouvardas</b>、<b>1990年</b>にギリシャ・テッサロニキで生まれる。多次元的なエレクトロニック・ミュージックの世界において、Christos はスピリチュアルな進化とリズム・動きを融合させた音を生み出す独自の能力で際立つ — スピリチュアルな深みと psy-trance のエネルギーを掛け合わせるコンポジション。<b>Padang Lab Series EP.1</b> を担当。<b>フェス：</b>Shankra Festival（スイス）、Tree Of Life Festival（トルコ）、Solstice Festival（オランダ）、Revision Festival（ギリシャ）、ギリシャ国内外でのインドア公演多数。<b>Padang Records から：</b><b>The Weight of Thought EP</b>（2025年7月）、<b>The Source Of Fear</b>、<b>Noctura</b>（Smokcid と）、<b>The Cruellest Master</b>（VA Reborn）。<b>2022年</b>、アンビエントとゆっくり進化する音楽への愛から、ダンス・シアター、短編、アート・ビデオのための作曲を開始。主たる目標：実験を通して音楽の境界を拡張し、人々のスピリチュアルな進化に貢献する — 聴く者を変容、自己認識、ひとつであることへの旅へと誘う状態を生み出すこと。連絡先: headweller_msc@hotmail.com。'
    },"Jandri": {
      en: '<b>Jandri</b>, Torrijos / Barcelona, Spain. His journey began with years of experience under the name <b>Guther</b> — a project started in <b>2008</b> in the Drum and Bass scene with classic vinyl. That first chapter laid the ground for an evolution toward deeper, psychedelic sound, giving birth in <b>2023</b> to the Jandri project, where he explores and fuses subgenres of <b>minimal techno (with a touch of psy)</b>, consolidating himself in today\'s psychedelic electronic scene. <b>Venues (Spain):</b> Club Zoreks (Lleida), Sala Golfus (Tarragona), Mama Mandawa (Barcelona), the iconic Florida 135 (Huesca), Sala Tren (Granada), Sala On (Madrid). <b>Festivals:</b> Moontagood Festival, Misa Psycodélika (Barcelona), The End of the World (Tarragona), Own Spirit Festival (Aragón), Arkana (Barcelona), Transition Fest. (Andalusia), La Casba Fest. (France), Visionart Fest. (Barcelona), Bass in the Park (Barcelona). An artist in full expansion, always faithful to the idea of connecting dancefloor and audience through a hypnotic, hard-hitting sonic journey.',
      es: '<b>Jandri</b>, Torrijos / Barcelona, España. Su viaje comenzó con años de experiencia bajo el nombre <b>Guther</b> — proyecto iniciado en <b>2008</b> en la escena del Drum and Bass con vinilos clásicos. Esa primera etapa sirvió de base para la evolución hacia sonidos más profundos y psicodélicos, dando origen en <b>2023</b> al proyecto Jandri, donde explora y fusiona subgéneros del <b>minimal techno (con pitada de psy)</b>, consolidándose en la escena electrónica psicodélica actual. <b>Venues (España):</b> Club Zoreks (Lleida), Sala Golfus (Tarragona), Mama Mandawa (Barcelona), la icónica Florida 135 (Huesca), Sala Tren (Granada), Sala On (Madrid). <b>Festivales:</b> Moontagood Festival, Misa Psycodélika (Barcelona), The End of the World (Tarragona), Own Spirit Festival (Aragón), Arkana (Barcelona), Transition Fest. (Andalucía), La Casba Fest. (Francia), Visionart Fest. (Barcelona), Bass in the Park (Barcelona). Artista en plena expansión, siempre fiel a la idea de conectar pista y público por un viaje sónico hipnótico y contundente.',
      de: '<b>Jandri</b>, Torrijos / Barcelona, Spanien. Seine Reise begann mit Jahren der Erfahrung unter dem Namen <b>Guther</b> — ein Projekt, das <b>2008</b> in der Drum-and-Bass-Szene mit klassischem Vinyl startete. Diese erste Etappe legte den Grundstein für eine Entwicklung hin zu tieferen, psychedelischen Klängen und brachte <b>2023</b> das Projekt Jandri hervor, in dem er Subgenres des <b>Minimal Techno (mit einem Hauch Psy)</b> erforscht und verschmelzt, sich so in der heutigen psychedelisch-elektronischen Szene etabliert. <b>Venues (Spanien):</b> Club Zoreks (Lleida), Sala Golfus (Tarragona), Mama Mandawa (Barcelona), das ikonische Florida 135 (Huesca), Sala Tren (Granada), Sala On (Madrid). <b>Festivals:</b> Moontagood Festival, Misa Psycodélika (Barcelona), The End of the World (Tarragona), Own Spirit Festival (Aragón), Arkana (Barcelona), Transition Fest. (Andalusien), La Casba Fest. (Frankreich), Visionart Fest. (Barcelona), Bass in the Park (Barcelona). Ein Künstler in voller Expansion, stets der Idee treu, Tanzfläche und Publikum durch eine hypnotische, wuchtige Klangreise zu verbinden.',
      fr: '<b>Jandri</b>, Torrijos / Barcelone, Espagne. Son parcours a débuté avec des années d\'expérience sous le nom de <b>Guther</b> — un projet lancé en <b>2008</b> dans la scène Drum and Bass, avec du vinyle classique. Cette première étape a posé les bases d\'une évolution vers des sons plus profonds et psychédéliques, donnant naissance en <b>2023</b> au projet Jandri, où il explore et fusionne les sous-genres du <b>minimal techno (avec une touche de psy)</b>, s\'imposant dans la scène électronique psychédélique actuelle. <b>Salles (Espagne) :</b> Club Zoreks (Lleida), Sala Golfus (Tarragone), Mama Mandawa (Barcelone), la mythique Florida 135 (Huesca), Sala Tren (Grenade), Sala On (Madrid). <b>Festivals :</b> Moontagood Festival, Misa Psycodélika (Barcelone), The End of the World (Tarragone), Own Spirit Festival (Aragon), Arkana (Barcelone), Transition Fest. (Andalousie), La Casba Fest. (France), Visionart Fest. (Barcelone), Bass in the Park (Barcelone). Artiste en pleine expansion, toujours fidèle à l\'idée de relier piste et public par un voyage sonore hypnotique et percutant.',
      ja: '<b>Jandri</b>、スペイン・トリホス／バルセロナ拠点。その旅は <b>Guther</b> 名義での長年のキャリアから始まった — <b>2008年</b>に Drum and Bass シーンでクラシックなヴァイナルを使って始めたプロジェクト。この最初の章がより深くサイケデリックなサウンドへの進化の土台となり、<b>2023年</b>に Jandri プロジェクトが誕生 — <b>minimal techno（with a touch of psy）</b> のサブジャンルを探求／融合し、現在のサイケデリック・エレクトロニック・シーンで地位を確立。<b>会場（スペイン）：</b>Club Zoreks（リェイダ）、Sala Golfus（タラゴナ）、Mama Mandawa（バルセロナ）、伝説の Florida 135（ウエスカ）、Sala Tren（グラナダ）、Sala On（マドリード）。<b>フェスティバル：</b>Moontagood Festival、Misa Psycodélika（バルセロナ）、The End of the World（タラゴナ）、Own Spirit Festival（アラゴン）、Arkana（バルセロナ）、Transition Fest.（アンダルシア）、La Casba Fest.（フランス）、Visionart Fest.（バルセロナ）、Bass in the Park（バルセロナ）。常に拡大中のアーティスト — 催眠的で力強いサウンドジャーニーで、ダンスフロアと観客をつなぐという理念に忠実であり続ける。'
    },"Jungle Haze": {
      en: '<b>Haffman</b>, Mexico. Jungle Haze is the Mexican producer\'s Dark Progressive and Psytech project — a sound rooted in hypnotic grooves, deep basslines and psychedelic atmospheres. The project explores the intersection between tribal rhythms and futuristic sound design, drawing inspiration from jungle landscapes, nocturnal rituals and altered states of perception. Crafting immersive sonic journeys designed for the underground psytrance dancefloor. <b>On Padang Records:</b> <b>Xaman</b> (10/2018), <b>Species</b> and <b>Sacred Ritual EP</b>; collaboration with Stopless on the <b>Technochtitlan EP</b> (2018). Contact: alarcon.haffman@gmail.com.',
      es: '<b>Haffman</b>, México. Jungle Haze es el proyecto Dark Progressive y Psytech del productor mexicano — un sonido enraizado en grooves hipnóticos, basslines profundos y atmósferas psicodélicas. El proyecto explora la intersección entre ritmos tribales y sound design futurista, inspirándose en paisajes de selva, rituales nocturnos y estados alterados de percepción. Crafting viajes sónicos inmersivos diseñados para la pista psytrance underground. <b>En Padang Records:</b> <b>Xaman</b> (10/2018), <b>Species</b> y <b>Sacred Ritual EP</b>; colaboración con Stopless en el <b>Technochtitlan EP</b> (2018). Contacto: alarcon.haffman@gmail.com.',
      de: '<b>Haffman</b>, Mexiko. Jungle Haze ist das Dark-Progressive- und Psytech-Projekt des mexikanischen Produzenten — ein in hypnotischen Grooves, tiefen Basslines und psychedelischen Atmosphären verwurzelter Sound. Das Projekt erforscht die Schnittstelle zwischen tribalen Rhythmen und futuristischem Sound Design, inspiriert von Dschungellandschaften, nächtlichen Ritualen und veränderten Wahrnehmungszuständen. Immersive Klangreisen, gestaltet für die Underground-Psytrance-Tanzfläche. <b>Auf Padang Records:</b> <b>Xaman</b> (10/2018), <b>Species</b> und <b>Sacred Ritual EP</b>; Kollaboration mit Stopless auf der <b>Technochtitlan EP</b> (2018). Kontakt: alarcon.haffman@gmail.com.',
      fr: '<b>Haffman</b>, Mexique. Jungle Haze est le projet Dark Progressive et Psytech du producteur mexicain — un son enraciné dans des grooves hypnotiques, des basslines profondes et des atmosphères psychédéliques. Le projet explore l\'intersection entre rythmes tribaux et sound design futuriste, puisant son inspiration dans les paysages de jungle, les rituels nocturnes et les états altérés de perception. Des voyages sonores immersifs conçus pour la piste psytrance underground. <b>Sur Padang Records :</b> <b>Xaman</b> (10/2018), <b>Species</b> et <b>Sacred Ritual EP</b> ; collaboration avec Stopless sur le <b>Technochtitlan EP</b> (2018). Contact : alarcon.haffman@gmail.com.',
      ja: '<b>Haffman</b>、メキシコ。Jungle Haze はそのメキシコ人プロデューサーによる Dark Progressive ／ Psytech プロジェクト — 催眠的なグルーヴ、深いベースライン、サイケデリックなアトモスフィアに根ざしたサウンド。トライバルなリズムとフューチャリスティックなサウンドデザインの交差点を探求し、ジャングルの風景、夜の儀式、知覚の変容状態からインスピレーションを得る。アンダーグラウンドの psytrance ダンスフロアのために設計された、没入的なサウンドジャーニーを生み出す。<b>Padang Records から：</b><b>Xaman</b>（2018年10月）、<b>Species</b>、<b>Sacred Ritual EP</b>。Stopless との <b>Technochtitlan EP</b>（2018）でコラボ。連絡先: alarcon.haffman@gmail.com。'
    },

    "Kaylee": {
      en: '<b>Michelle Kelly Leemann</b>, Zürich / NYC. DJ and producer — Techno and Night-Psychedelic Trance. Also performs as <b>KAYLEE!</b>. Co-creator of the <b>Art Materials</b> project, bridging Techno and Psy. Creator of <b>MODULAR FESTIVAL</b>. Part of the Padang Records crew.',
      es: '<b>Michelle Kelly Leemann</b>, Zúrich / NYC. DJ y productora — Techno y Night-Psychedelic Trance. También se presenta como <b>KAYLEE!</b>. Co-creadora del proyecto <b>Art Materials</b>, que tiende un puente creativo entre Techno y Psy. Creadora del <b>MODULAR FESTIVAL</b>. Integra el equipo de Padang Records.',
      de: '<b>Michelle Kelly Leemann</b>, Zürich / NYC. DJ und Produzentin — Techno und Night-Psychedelic Trance. Tritt auch als <b>KAYLEE!</b> auf. Mit-Schöpferin des Projekts <b>Art Materials</b>, das eine kreative Brücke zwischen Techno und Psy schlägt. Schöpferin des <b>MODULAR FESTIVAL</b>. Teil des Padang-Records-Teams.',
      fr: '<b>Michelle Kelly Leemann</b>, Zurich / NYC. DJ et productrice — Techno et Night-Psychedelic Trance. Se produit également sous <b>KAYLEE!</b>. Co-créatrice du projet <b>Art Materials</b>, qui fait le pont créatif entre Techno et Psy. Créatrice du <b>MODULAR FESTIVAL</b>. Membre de l\\\'équipe Padang Records.',
      ja: '<b>Michelle Kelly Leemann</b>、チューリッヒ／NYC 拠点。DJ ／プロデューサー — Techno と Night-Psychedelic Trance。<b>KAYLEE!</b> としても活動。プロジェクト <b>Art Materials</b> の共同創作者で、Techno と Psy をつなぐ創造的な橋。<b>MODULAR FESTIVAL</b> の創設者。Padang Records チームの一員。'
    },"Kilbee": {
      en: '<b>Gabriel Gómez</b>, Chile — born in <b>Concepción in 1977</b> (cradle of Chilean rock). More than 15 years producing electronic music in different styles. He discovered music during his university years when jazz was his passion; he enrolled in the jazz school of <b>Marlón Romero</b> (renowned Chilean musician), studying electric bass for years before moving into synthesizer-generated sounds and electronic beats. <b>Aliases:</b> Rollercoaster / Paracoaster / Arcturians / Gao. In <b>2018</b> he began exploring Minimal Techno with a touch of psychedelia, creating the Kilbee project — designed to make the listener dance and have fun. As Kilbee he explores the more hypnotic side of psytrance/minimal techno with minimalist constructions and a focus on detail.',
      es: '<b>Gabriel Gómez</b>, Chile — nacido en <b>Concepción en 1977</b> (cuna del rock chileno). Más de 15 años produciendo electrónica en diferentes estilos. Descubrió la música en los años universitarios cuando el jazz era su pasión; entró en la escuela de jazz de <b>Marlón Romero</b> (renombrado músico chileno), estudiando bajo eléctrico durante años antes de migrar a sonidos generados por sintetizadores y beats electrónicos. <b>Alias:</b> Rollercoaster / Paracoaster / Arcturians / Gao. En <b>2018</b> empezó a explorar el Techno Minimal con toque de psicodelia, creando el proyecto Kilbee — pensado para hacer bailar y divertir al que escucha. Como Kilbee explora la vertiente más hipnótica del psytrance/techno minimal con construcciones minimalistas y foco en el detalle.',
      de: '<b>Gabriel Gómez</b>, Chile — geboren <b>1977 in Concepción</b> (Wiege des chilenischen Rock). Mehr als 15 Jahre Produktion elektronischer Musik in unterschiedlichen Stilen. Er entdeckte die Musik während seines Studiums, als Jazz seine Leidenschaft war; er trat in die Jazz-Schule von <b>Marlón Romero</b> (renommierter chilenischer Musiker) ein und studierte jahrelang E-Bass, bevor er zu synthesizer-generierten Klängen und elektronischen Beats wechselte. <b>Aliase:</b> Rollercoaster / Paracoaster / Arcturians / Gao. <b>2018</b> begann er, Minimal Techno mit einem Hauch Psychedelia zu erforschen, und schuf das Projekt Kilbee — gedacht, um den Hörer zum Tanzen zu bringen und zu unterhalten. Als Kilbee erforscht er die hypnotischere Seite des Psytrance/Minimal Techno mit minimalistischen Konstruktionen und Detailfokus.',
      fr: '<b>Gabriel Gómez</b>, Chili — né à <b>Concepción en 1977</b> (berceau du rock chilien). Plus de 15 ans de production de musique électronique dans différents styles. Il découvre la musique pendant ses années universitaires, alors que le jazz était sa passion ; il rejoint l\'école de jazz de <b>Marlón Romero</b> (musicien chilien renommé), étudiant la basse électrique pendant des années avant de basculer vers les sons générés par synthétiseurs et les beats électroniques. <b>Alias :</b> Rollercoaster / Paracoaster / Arcturians / Gao. En <b>2018</b>, il commence à explorer le Minimal Techno teinté de psychédélie en créant le projet Kilbee — pensé pour faire danser et amuser l\'auditeur. Sous Kilbee, il explore le versant le plus hypnotique du psytrance / minimal techno, avec des constructions minimalistes et un soin du détail.',
      ja: '<b>Gabriel Gómez</b>、チリ — <b>1977年にコンセプシオン</b>（チリ・ロックの揺りかご）で生まれる。15年以上にわたり様々なスタイルでエレクトロニック音楽を制作。大学時代にジャズに情熱を注ぎ音楽と出会い、著名なチリ人ミュージシャン <b>Marlón Romero</b> のジャズ・スクールに入学、数年間エレキベースを学んだのち、シンセサイザー由来のサウンドとエレクトロニック・ビートへと移行。<b>エイリアス：</b>Rollercoaster／Paracoaster／Arcturians／Gao。<b>2018年</b>、サイケデリアのタッチを加えたミニマル・テクノを探求しはじめ、聴く者を踊らせ楽しませることを目的とした Kilbee プロジェクトを立ち上げた。Kilbee 名義では、ミニマリスティックな構築と細部へのこだわりで、psytrance／ミニマル・テクノのより催眠的な側面を探求する。'
    },

    "Mallki": {
      en: '"Domestic Pirates". Peruvian based in Barcelona, <b>official Padang Records DJ</b>. Creator of <b>Arkana Festival</b> — 13+ years in the Sacred Valley of the Incas, Peru. Versatile DJ moving between downtempo, progressive house, deep house, techno, minimal techno and psytrance. <br><br><b>South America:</b> Universo Paralello (UP Club · BR), Pulsar Festival, Zubuya, Terra em Transe, Resonar, Aho Festival (BR), Earthdance Argentina, Inchala (Uruguay), Amazonas Andes (Bolivia), Arkana Festival (Peru). <b>Mexico:</b> Ometeotl, Psycristrance, Ocelot, Space Odissey 3, Promise Land, Poison Festival, MoDem teaser MX. <b>Europe:</b> Bermuda Gathering (Finland), Own Spirit Festival (Spain), Atman Festival (Portugal), Eudaimonia Gathering (Greece), MO:DEM (Croatia), Suti Festival (Portugal). Curated <b>VA Nukaya</b> (Padang Records, 05/2024) — 19 global producers with reborn Inca rhythms.',
      es: '"Domestic Pirates". Peruano radicado en Barcelona, <b>DJ oficial de Padang Records</b>. Creador del <b>Arkana Festival</b> — 13+ años en el Valle Sagrado de los Incas, Perú. DJ versátil que transita por downtempo, progressive house, deep house, techno, minimal techno y psytrance. <br><br><b>Sudamérica:</b> Universo Paralello (UP Club · BR), Pulsar Festival, Zubuya, Terra em Transe, Resonar, Aho Festival (BR), Earthdance Argentina, Inchala (Uruguay), Amazonas Andes (Bolivia), Arkana Festival (Perú). <b>México:</b> Ometeotl, Psycristrance, Ocelot, Space Odissey 3, Promise Land, Poison Festival, MoDem teaser MX. <b>Europa:</b> Bermuda Gathering (Finlandia), Own Spirit Festival (España), Atman Festival (Portugal), Eudaimonia Gathering (Grecia), MO:DEM (Croacia), Suti Festival (Portugal). Curó <b>VA Nukaya</b> (Padang Records, 05/2024) — 19 productores globales con ritmos Inca renacidos.',
      de: '"Domestic Pirates". Peruaner mit Sitz in Barcelona, <b>offizieller Padang-Records-DJ</b>. Schöpfer des <b>Arkana Festival</b> — 13+ Jahre im Heiligen Tal der Inka, Peru. Vielseitiger DJ zwischen Downtempo, Progressive House, Deep House, Techno, Minimal Techno und Psytrance. <br><br><b>Südamerika:</b> Universo Paralello (UP Club · BR), Pulsar Festival, Zubuya, Terra em Transe, Resonar, Aho Festival (BR), Earthdance Argentinien, Inchala (Uruguay), Amazonas Andes (Bolivien), Arkana Festival (Peru). <b>Mexiko:</b> Ometeotl, Psycristrance, Ocelot, Space Odissey 3, Promise Land, Poison Festival, MoDem-Teaser MX. <b>Europa:</b> Bermuda Gathering (Finnland), Own Spirit Festival (Spanien), Atman Festival (Portugal), Eudaimonia Gathering (Griechenland), MO:DEM (Kroatien), Suti Festival (Portugal). Kuratierte <b>VA Nukaya</b> (Padang Records, 05/2024) — 19 globale Produzenten mit wiedergeborenen Inka-Rhythmen.',
      fr: '« Domestic Pirates ». Péruvien basé à Barcelone, <b>DJ officiel de Padang Records</b>. Créateur de l\'<b>Arkana Festival</b> — 13+ ans dans la Vallée Sacrée des Incas, Pérou. DJ polyvalent naviguant entre downtempo, progressive house, deep house, techno, minimal techno et psytrance. <br><br><b>Amérique du Sud :</b> Universo Paralello (UP Club · BR), Pulsar Festival, Zubuya, Terra em Transe, Resonar, Aho Festival (BR), Earthdance Argentine, Inchala (Uruguay), Amazonas Andes (Bolivie), Arkana Festival (Pérou). <b>Mexique :</b> Ometeotl, Psycristrance, Ocelot, Space Odissey 3, Promise Land, Poison Festival, MoDem teaser MX. <b>Europe :</b> Bermuda Gathering (Finlande), Own Spirit Festival (Espagne), Atman Festival (Portugal), Eudaimonia Gathering (Grèce), MO:DEM (Croatie), Suti Festival (Portugal). A curaté <b>VA Nukaya</b> (Padang Records, 05/2024) — 19 producteurs internationaux et rythmes incas renaissants.',
      ja: '「Domestic Pirates」。バルセロナ拠点のペルー人、<b>Padang Records 公式 DJ</b>。<b>Arkana Festival</b> の創設者 — ペルー・インカ聖なる谷で13年以上。ダウンテンポ、プログレッシブ・ハウス、ディープ・ハウス、テクノ、ミニマル・テクノ、psytrance を行き来する多才な DJ。<br><br><b>南米：</b>Universo Paralello（UP Club · BR）、Pulsar Festival、Zubuya、Terra em Transe、Resonar、Aho Festival（BR）、Earthdance アルゼンチン、Inchala（ウルグアイ）、Amazonas Andes（ボリビア）、Arkana Festival（ペルー）。<b>メキシコ：</b>Ometeotl、Psycristrance、Ocelot、Space Odissey 3、Promise Land、Poison Festival、MoDem teaser MX。<b>ヨーロッパ：</b>Bermuda Gathering（フィンランド）、Own Spirit Festival（スペイン）、Atman Festival（ポルトガル）、Eudaimonia Gathering（ギリシャ）、MO:DEM（クロアチア）、Suti Festival（ポルトガル）。Padang Records で <b>VA Nukaya</b>（2024年5月）をキュレーション — 世界19組のプロデューサーと甦るインカのリズム。'
    },

    "Massive Psy": {
      en: '<b>Shahabeddin</b>, born in Tehran, Iran. Moved to Armenia in 2007 and was one of the first DJs to introduce psytrance into Armenian nightlife. Dove into Dark Progressive Psytrance and Dark Progressive Techno (Zenonesque). Founder of <b>QUANTUM LAB</b> and <b>NAYAMA FESTIVAL</b>; member of AHOORA FESTIVAL. Part of Padang Records — exclusive set "MASSIVE PSY for PADANG RECORDS" (06/2024). DJ since 2005.',
      es: '<b>Shahabeddin</b>, nacido en Teherán, Irán. Se mudó a Armenia en 2007 y fue uno de los primeros DJs en introducir el psytrance en la vida nocturna armenia. Se sumergió en el Dark Progressive Psytrance y el Dark Progressive Techno (Zenonesque). Fundador de <b>QUANTUM LAB</b> y <b>NAYAMA FESTIVAL</b>; miembro del AHOORA FESTIVAL. Integra Padang Records — set exclusivo "MASSIVE PSY for PADANG RECORDS" (06/2024). DJ desde 2005.',
      de: '<b>Shahabeddin</b>, geboren in Teheran, Iran. 2007 nach Armenien gezogen und einer der ersten DJs, die Psytrance ins armenische Nachtleben brachten. Tauchte in Dark Progressive Psytrance und Dark Progressive Techno (Zenonesque) ein. Gründer von <b>QUANTUM LAB</b> und <b>NAYAMA FESTIVAL</b>; Mitglied des AHOORA FESTIVAL. Teil von Padang Records — exklusives Set "MASSIVE PSY for PADANG RECORDS" (06/2024). DJ seit 2005.',
      fr: '<b>Shahabeddin</b>, né à Téhéran, Iran. A déménagé en Arménie en 2007 et fut l\'un des premiers DJs à introduire le psytrance dans la vie nocturne arménienne. Plongé dans le Dark Progressive Psytrance et le Dark Progressive Techno (Zenonesque). Fondateur de <b>QUANTUM LAB</b> et <b>NAYAMA FESTIVAL</b>; membre de AHOORA FESTIVAL. Intègre Padang Records — set exclusif « MASSIVE PSY for PADANG RECORDS » (06/2024). DJ depuis 2005.',
      ja: '<b>Shahabeddin</b>、イラン・テヘラン生まれ。2007年にアルメニアへ移り、アルメニアのナイトライフに psytrance を持ち込んだ最初の DJ の一人。Dark Progressive Psytrance と Dark Progressive Techno（Zenonesque）に深く没入。<b>QUANTUM LAB</b> と <b>NAYAMA FESTIVAL</b> の創設者、AHOORA FESTIVAL のメンバー。Padang Records の一員 — エクスクルーシブ・セット「MASSIVE PSY for PADANG RECORDS」（2024年6月）。2005年から DJ 活動。'
    },"Meerkat": {
      en: '<b>Mark Ahessy</b>, southern Ireland. He began his contribution to the Irish psychedelic scene by promoting events all around the country. It didn\'t take long for the passion to evolve into a more hands-on approach — the Meerkat initiative was born. Initially a DJ project, the production bug soon bit and Mark started producing his own brand of psychedelia. His musical range goes from <b>groovy Psy tech</b> to <b>dark playful prog</b>, constantly pushing the limits of the sonic palette. Founder of <b>Enter Mushroom Festival</b> (Ireland). <b>On Padang Records:</b> <b>2 Minutes to Midnight</b> (02/2020), <b>Sodium Pentathol</b> with Zentrix and <b>Project Brue Beam</b> (VA Nukaya). <b>Festivals:</b> Lost Theory, Sunshine, Arkana, Solstice, Ometeotl. Contact: markahessy@yahoo.com.',
      es: '<b>Mark Ahessy</b>, sur de Irlanda. Comenzó su contribución a la escena psicodélica irlandesa promoviendo eventos por todo el país. No tardó mucho para que la pasión evolucionara hacia un enfoque más hands-on — la iniciativa Meerkat nació. Inicialmente proyecto de DJ, el bug de la producción pronto lo mordió y Mark empezó a producir su propia marca de psicodelia. Su rango musical va de <b>groovy Psy tech</b> a <b>dark playful prog</b>, empujando constantemente los límites de la paleta sónica. Fundador del <b>Enter Mushroom Festival</b> (Irlanda). <b>En Padang Records:</b> <b>2 Minutes to Midnight</b> (02/2020), <b>Sodium Pentathol</b> con Zentrix y <b>Project Brue Beam</b> (VA Nukaya). <b>Festivales:</b> Lost Theory, Sunshine, Arkana, Solstice, Ometeotl. Contacto: markahessy@yahoo.com.',
      de: '<b>Mark Ahessy</b>, Süd-Irland. Er begann seinen Beitrag zur irischen psychedelischen Szene mit der Promotion von Events im ganzen Land. Es dauerte nicht lange, bis die Leidenschaft sich zu einem hands-on-Ansatz weiterentwickelte — die Initiative Meerkat war geboren. Ursprünglich ein DJ-Projekt, packte ihn bald der Produktions-Virus und Mark begann, seine eigene Form von Psychedelia zu produzieren. Seine musikalische Bandbreite reicht von <b>groovigem Psy tech</b> bis zu <b>dark playful prog</b> und verschiebt ständig die Grenzen der Klangpalette. Gründer des <b>Enter Mushroom Festival</b> (Irland). <b>Auf Padang Records:</b> <b>2 Minutes to Midnight</b> (02/2020), <b>Sodium Pentathol</b> mit Zentrix und <b>Project Brue Beam</b> (VA Nukaya). <b>Festivals:</b> Lost Theory, Sunshine, Arkana, Solstice, Ometeotl. Kontakt: markahessy@yahoo.com.',
      fr: '<b>Mark Ahessy</b>, sud de l\'Irlande. Il a commencé sa contribution à la scène psychédélique irlandaise en organisant des événements à travers tout le pays. Il n\'a pas fallu longtemps pour que la passion évolue vers une approche plus hands-on — l\'initiative Meerkat est née. D\'abord projet de DJ, le virus de la production l\'a vite saisi et Mark a commencé à produire sa propre marque de psychédélie. Son spectre musical va du <b>groovy Psy tech</b> au <b>dark playful prog</b>, repoussant constamment les limites de la palette sonore. Fondateur de l\'<b>Enter Mushroom Festival</b> (Irlande). <b>Sur Padang Records :</b> <b>2 Minutes to Midnight</b> (02/2020), <b>Sodium Pentathol</b> avec Zentrix et <b>Project Brue Beam</b> (VA Nukaya). <b>Festivals :</b> Lost Theory, Sunshine, Arkana, Solstice, Ometeotl. Contact : markahessy@yahoo.com.',
      ja: '<b>Mark Ahessy</b>、アイルランド南部出身。アイルランドのサイケデリック・シーンへの貢献は、全国でイベントを企画することから始まった。その情熱はすぐにより実践的なアプローチへと進化し — Meerkat プロジェクトが誕生。当初は DJ プロジェクトだったが、すぐに制作のバグに噛まれ、Mark は自分自身のサイケデリアを生み出し始めた。音楽の幅は <b>groovy Psy tech</b> から <b>dark playful prog</b> まで、常にサウンド・パレットの境界を押し広げる。<b>Enter Mushroom Festival</b>（アイルランド）の創設者。<b>Padang Records から：</b><b>2 Minutes to Midnight</b>（2020年2月）、Zentrix との <b>Sodium Pentathol</b>、<b>Project Brue Beam</b>（VA Nukaya）。<b>フェス：</b>Lost Theory、Sunshine、Arkana、Solstice、Ometeotl。連絡先: markahessy@yahoo.com。'
    },"Musgolino": {
      en: '<b>Pablo Larrán</b>, Madrid, Spain. The creative mind behind the Musgolino character — where he unfolds his musical fantasies, building a sonic universe through dark landscapes, organic textures and cinematic atmospheres. Flowing between the hypnotic pulse of techno and the immersive depth of progressive, Musgolino — like the person behind it — is in constant evolution and exploration, incorporating new sonic elements discovered along the way, such as heavy distortions and Tekno influences. Since <b>2018</b> the project has consolidated with releases on Padang Records. <b>Festivals:</b> Own Spirit, Living Village, We Dark One. <b>On Padang Records:</b> <b>What?</b> (Technomad II, 05/2025), <b>Reminiscencias</b> (VA Nukaya, 05/2024) and <b>Orgelon</b>; live with Monkey Mind at Own Spirit 2023. Pablo describes himself as a "music lover and collector of music and sounds". Based in Madrid, he has been actively part of the Spanish psychedelic scene as an artist and event organizer for over 10 years.',
      es: '<b>Pablo Larrán</b>, Madrid, España. La mente creativa detrás del personaje Musgolino — donde despliega sus fantasías musicales creando un universo sónico a través de paisajes oscuros, texturas orgánicas y atmósferas cinematográficas. Fluyendo entre el pulso hipnótico del techno y la profundidad inmersiva del progresivo, Musgolino — como la persona detrás — está en constante evolución y exploración, incorporando nuevos elementos sónicos descubiertos por el camino, como distorsiones fuertes e influencias del Tekno. Desde <b>2018</b> el proyecto se consolidó con releases en Padang Records. <b>Festivales:</b> Own Spirit, Living Village, We Dark One. <b>En Padang Records:</b> <b>What?</b> (Technomad II, 05/2025), <b>Reminiscencias</b> (VA Nukaya, 05/2024) y <b>Orgelon</b>; live con Monkey Mind en Own Spirit 2023. Pablo se describe como "music lover and collector of music and sounds". Basado en Madrid, participa activamente en la escena psicodélica española como artista y organizador de eventos hace más de 10 años.',
      de: '<b>Pablo Larrán</b>, Madrid, Spanien. Der kreative Kopf hinter der Figur Musgolino — wo er seine musikalischen Fantasien entfaltet und ein klangliches Universum aus düsteren Landschaften, organischen Texturen und kinematischen Atmosphären erschafft. Fließend zwischen dem hypnotischen Puls des Techno und der immersiven Tiefe des Progressive, befindet sich Musgolino — wie die Person dahinter — in ständiger Evolution und Erforschung, integriert dabei neue klangliche Elemente, die er unterwegs entdeckt, wie starke Distortions und Tekno-Einflüsse. Seit <b>2018</b> hat sich das Projekt mit Releases auf Padang Records gefestigt. <b>Festivals:</b> Own Spirit, Living Village, We Dark One. <b>Auf Padang Records:</b> <b>What?</b> (Technomad II, 05/2025), <b>Reminiscencias</b> (VA Nukaya, 05/2024) und <b>Orgelon</b>; Live mit Monkey Mind beim Own Spirit 2023. Pablo beschreibt sich selbst als "music lover and collector of music and sounds". In Madrid lebend, ist er seit über 10 Jahren als Künstler und Eventorganisator aktiver Teil der spanischen psychedelischen Szene.',
      fr: '<b>Pablo Larrán</b>, Madrid, Espagne. L\'esprit créatif derrière le personnage de Musgolino — où il déploie ses fantaisies musicales et construit un univers sonore à travers paysages sombres, textures organiques et atmosphères cinématographiques. Naviguant entre la pulsation hypnotique du techno et la profondeur immersive du progressive, Musgolino — comme la personne derrière — est en évolution et exploration constantes, intégrant les nouveaux éléments sonores découverts en chemin, comme des distorsions fortes et des influences Tekno. Depuis <b>2018</b>, le projet s\'est consolidé avec des sorties sur Padang Records. <b>Festivals :</b> Own Spirit, Living Village, We Dark One. <b>Sur Padang Records :</b> <b>What?</b> (Technomad II, 05/2025), <b>Reminiscencias</b> (VA Nukaya, 05/2024) et <b>Orgelon</b> ; live avec Monkey Mind à Own Spirit 2023. Pablo se décrit comme un « music lover and collector of music and sounds ». Basé à Madrid, il participe activement à la scène psychédélique espagnole comme artiste et organisateur d\'événements depuis plus de 10 ans.',
      ja: '<b>Pablo Larrán</b>、スペイン・マドリード出身。Musgolino というキャラクターの背後にいるクリエイティブな頭脳 — ダークな風景、オーガニックなテクスチャ、シネマティックなアトモスフィアを通して音楽的ファンタジーを展開し、サウンドの宇宙を築き上げる。テクノの催眠的なパルスとプログレッシブの没入的な深みの間を流れる Musgolino は、その背後にいる人物と同様、常に進化／探求の途上にあり、強い歪みや Tekno の影響など、道中で発見した新しいサウンド要素を取り込んでいく。<b>2018年</b>以降、Padang Records でのリリースを通してプロジェクトを確立。<b>フェス：</b>Own Spirit、Living Village、We Dark One。<b>Padang Records から：</b><b>What?</b>（Technomad II、2025年5月）、<b>Reminiscencias</b>（VA Nukaya、2024年5月）、<b>Orgelon</b>。Own Spirit 2023 で Monkey Mind とライブ。Pablo は自分自身を「music lover and collector of music and sounds」と表現する。マドリードを拠点に、10年以上にわたりスペインのサイケデリック・シーンでアーティストとして、またイベント・オーガナイザーとして活動している。'
    },

    "Myrtox": {
      en: 'Stuttgart, Germany. Also works as a professional mastering engineer (Mastering Bunker). On Padang Records: <b>Freak Show</b> (VA Nukaya), <b>EΛT MΛRBLΣZ</b> with MultiTul and <b>Abstract Evolution</b> with Mentor. Live @ U&D Festival in 2015.',
      es: 'Stuttgart, Alemania. También trabaja como mastering profesional (Mastering Bunker). En Padang Records: <b>Freak Show</b> (VA Nukaya), <b>EΛT MΛRBLΣZ</b> con MultiTul y <b>Abstract Evolution</b> con Mentor. Live @ U&D Festival en 2015.',
      de: 'Stuttgart, Deutschland. Arbeitet auch als professioneller Mastering-Engineer (Mastering Bunker). Auf Padang Records: <b>Freak Show</b> (VA Nukaya), <b>EΛT MΛRBLΣZ</b> mit MultiTul und <b>Abstract Evolution</b> mit Mentor. Live @ U&D Festival 2015.',
      fr: 'Stuttgart, Allemagne. Travaille également comme ingénieur de mastering professionnel (Mastering Bunker). Sur Padang Records : <b>Freak Show</b> (VA Nukaya), <b>EΛT MΛRBLΣZ</b> avec MultiTul et <b>Abstract Evolution</b> avec Mentor. Live @ U&D Festival en 2015.',
      ja: 'ドイツ・シュトゥットガルト。プロのマスタリング・エンジニアとしても活動（Mastering Bunker）。Padang Records から：<b>Freak Show</b>（VA Nukaya）、MultiTul と <b>EΛT MΛRBLΣZ</b>、Mentor と <b>Abstract Evolution</b>。2015年 U&D Festival でライブ。'
    },"Naias": {
      en: '<b>Paulina Orwat</b>, based in Lisbon, Portugal. <b>Official Padang Records DJane</b>. Naias loves dark and groovy rave music — she crafts unique, dreamlike, mind-bending experiences. Her interests swing across psychedelic music, especially <b>minimal techno, Dark Prog and Forest</b> — a selection that stitches hypnotic layers to underground energy. Delivered <b>Padang Lab Series EP.16</b> @ Omtara Festival.',
      es: '<b>Paulina Orwat</b>, basada en Lisboa, Portugal. <b>DJane oficial de Padang Records</b>. Naias adora la música rave dark y groovy — crea experiencias únicas, oníricas y mind-bending. Sus intereses oscilan por la música psicodélica, especialmente <b>minimal techno, Dark Prog y Forest</b> — selección que cose capas hipnóticas a la energía underground. Presentó la <b>Padang Lab Series EP.16</b> @ Omtara Festival.',
      de: '<b>Paulina Orwat</b>, ansässig in Lissabon, Portugal. <b>Offizielle Padang-Records-DJane</b>. Naias liebt dunkle und groovige Rave-Musik — sie schafft einzigartige, traumartige, mind-bending Erlebnisse. Ihre Interessen schwingen durch die psychedelische Musik, besonders <b>Minimal Techno, Dark Prog und Forest</b> — eine Auswahl, die hypnotische Schichten mit Underground-Energie zusammennäht. Lieferte <b>Padang Lab Series EP.16</b> beim Omtara Festival.',
      fr: '<b>Paulina Orwat</b>, basée à Lisbonne, Portugal. <b>DJane officielle de Padang Records</b>. Naias adore la musique rave dark et groovy — elle façonne des expériences uniques, oniriques et mind-bending. Ses intérêts oscillent dans la musique psychédélique, en particulier <b>minimal techno, Dark Prog et Forest</b> — une sélection qui coud des couches hypnotiques à l\'énergie underground. A livré la <b>Padang Lab Series EP.16</b> @ Omtara Festival.',
      ja: '<b>Paulina Orwat</b>、ポルトガル・リスボン拠点。<b>Padang Records 公式 DJane</b>。Naias は dark でグルーヴィーなレイヴ・ミュージックを愛し — 独自の、夢のような、マインドベンディングな体験を生み出す。関心はサイケデリック音楽全般、特に <b>minimal techno、Dark Prog、Forest</b> に向く — 催眠的なレイヤーをアンダーグラウンドのエネルギーに縫い合わせるセレクション。<b>Padang Lab Series EP.16</b> @ Omtara Festival を担当。'
    },

    "Niobiun": {
      en: '<b>Josué Fernandes</b>, Brazil. <b>Dark Prog</b> project created in 2015 — sound influenced by techno, minimal, dark psy and <b>alternative metal</b>. Results in ambient, abstract progressive that travels between distinct musical variations and sonic experiments. Released the album <b>Intersections</b> on Padang Records (06/2021). Track <b>Universal Clock</b> (VA Exogenesis); collaborations <b>Space Artfact</b> and <b>Mind Echoes</b> with Orbsynth, both on Padang Records. Contact: josueb.fernandes@gmail.com.',
      es: '<b>Josué Fernandes</b>, Brasil. Proyecto de <b>Dark Prog</b> creado en 2015 — sonido influenciado por techno, minimal, dark psy y <b>metal alternativo</b>. Resulta en progresivo ambiente y abstracto que viaja entre distintas variaciones musicales y experimentos sonoros. Lanzó el álbum <b>Intersections</b> en Padang Records (06/2021). Track <b>Universal Clock</b> (VA Exogenesis); colaboraciones <b>Space Artfact</b> y <b>Mind Echoes</b> con Orbsynth, ambos en Padang Records. Contacto: josueb.fernandes@gmail.com.',
      de: '<b>Josué Fernandes</b>, Brasilien. <b>Dark-Prog</b>-Projekt 2015 ins Leben gerufen — der Sound von Techno, Minimal, Dark Psy und <b>Alternative Metal</b> beeinflusst. Ergibt ambient-progressive und abstrakte Musik, die sich zwischen verschiedenen musikalischen Variationen und klanglichen Experimenten bewegt. Veröffentlichte das Album <b>Intersections</b> auf Padang Records (06/2021). Track <b>Universal Clock</b> (VA Exogenesis); Kollaborationen <b>Space Artfact</b> und <b>Mind Echoes</b> mit Orbsynth, beide auf Padang Records. Kontakt: josueb.fernandes@gmail.com.',
      fr: '<b>Josué Fernandes</b>, Brésil. Projet <b>Dark Prog</b> créé en 2015 — son influencé par le techno, le minimal, le dark psy et le <b>métal alternatif</b>. Aboutit à un progressive ambient et abstrait qui voyage entre des variations musicales distinctes et des expériences sonores. A sorti l\'album <b>Intersections</b> sur Padang Records (06/2021). Morceau <b>Universal Clock</b> (VA Exogenesis); collaborations <b>Space Artfact</b> et <b>Mind Echoes</b> avec Orbsynth, toutes deux sur Padang Records. Contact : josueb.fernandes@gmail.com.',
      ja: '<b>Josué Fernandes</b>、ブラジル出身。2015年に立ち上げた <b>Dark Prog</b> プロジェクト — テクノ、ミニマル、ダークサイ、<b>オルタナティブメタル</b> の影響を受けたサウンド。様々な音楽的バリエーションとサウンド実験を行き来する、アンビエント＆アブストラクトなプログレッシブを生み出す。Padang Records からアルバム <b>Intersections</b>（2021年6月）をリリース。<b>Universal Clock</b>（VA Exogenesis）、Orbsynth との共作 <b>Space Artfact</b>、<b>Mind Echoes</b>（共に Padang Records）。連絡先: josueb.fernandes@gmail.com。'
    },

    "Nuit Noire": {
      en: 'Christina. Queer DJ based in Montréal, Canada — <b>Padang Records label DJ</b>. Mixes techno, dark prog and psytech. Curated <b>VA The Nightmare</b> (08/2025) on Padang Records — a journey where frightening memories and pleasure collide. Recent sets: Sanctuary 2025 (Bain Mathieu, Montreal), Arkana showcase Montréal 2025 and Era Festival 2024.',
      es: 'Christina. Queer DJ basada en Montreal, Canadá — <b>label DJ de Padang Records</b>. Mezcla techno, dark prog y psytech. Curó <b>VA The Nightmare</b> (08/2025) en Padang Records — un viaje donde memorias aterradoras y placer colisionan. Sets recientes: Sanctuary 2025 (Bain Mathieu, Montreal), Arkana showcase Montréal 2025 y Era Festival 2024.',
      de: 'Christina. Queere DJ in Montréal, Kanada — <b>Padang-Records-Label-DJ</b>. Mischt Techno, Dark Prog und Psytech. Kuratierte <b>VA The Nightmare</b> (08/2025) auf Padang Records — eine Reise, in der erschreckende Erinnerungen und Lust kollidieren. Aktuelle Sets: Sanctuary 2025 (Bain Mathieu, Montreal), Arkana Showcase Montréal 2025 und Era Festival 2024.',
      fr: 'Christina. DJ queer basée à Montréal, Canada — <b>label DJ de Padang Records</b>. Mélange techno, dark prog et psytech. A curaté <b>VA The Nightmare</b> (08/2025) sur Padang Records — un voyage où mémoires effrayantes et plaisir entrent en collision. Sets récents : Sanctuary 2025 (Bain Mathieu, Montréal), Arkana showcase Montréal 2025 et Era Festival 2024.',
      ja: 'Christina。カナダ・モントリオール拠点のクィア DJ — <b>Padang Records レーベル DJ</b>。Techno、Dark Prog、Psytech をミックス。Padang Records で <b>VA The Nightmare</b>（2025年8月）をキュレーション — 恐ろしい記憶と快楽が衝突する旅。最近のセット：Sanctuary 2025（Bain Mathieu、モントリオール）、Arkana showcase Montréal 2025、Era Festival 2024。'
    },

    "Orbsynth": {
      en: 'Brazilian artist associated with <b>Padang Records</b>. Collaborations with Niobiun on <b>Space Artfact</b> and <b>Mind Echoes</b> (both on Padang). Psy-trance / dark progressive.',
      es: 'Artista brasileño asociado a <b>Padang Records</b>. Colaboraciones con Niobiun en <b>Space Artfact</b> y <b>Mind Echoes</b> (ambos en Padang). Psy-trance / dark progressive.',
      de: 'Brasilianischer Künstler bei <b>Padang Records</b>. Kollaborationen mit Niobiun bei <b>Space Artfact</b> und <b>Mind Echoes</b> (beide auf Padang). Psy-Trance / Dark Progressive.',
      fr: 'Artiste brésilien associé à <b>Padang Records</b>. Collaborations avec Niobiun sur <b>Space Artfact</b> et <b>Mind Echoes</b> (toutes deux sur Padang). Psy-trance / dark progressive.',
      ja: '<b>Padang Records</b> 所属のブラジル人アーティスト。Niobiun と <b>Space Artfact</b> および <b>Mind Echoes</b>（ともに Padang）でコラボ。Psy-trance ／ Dark Progressive。'
    },

    "Paracozm": {
      en: '<b>Diego Brinker</b>, southern Brazil. Defined as a meticulously crafted imaginary realm of fantasy, originating within the confines of cognition itself. Deep, enigmatic, velvety and visionary soundscapes. <b>On Padang Records:</b> <b>Packet Loss</b> (11/2019), <b>Paracozm Redux</b> (06/2016); remixes Hellquist (Northern Night) and Pspiralife (Liquid Nails); track <b>Oni</b> on VA Reborn. <b>Festivals:</b> Earthdance RS, Flux Indoor.',
      es: '<b>Diego Brinker</b>, sur de Brasil. Definido como un reino imaginario meticulosamente construido de fantasía, originado dentro de los confines de la propia cognición. Soundscapes profundos, enigmáticos, aterciopelados y visionarios. <b>En Padang Records:</b> <b>Packet Loss</b> (11/2019), <b>Paracozm Redux</b> (06/2016); remixes Hellquist (Northern Night) y Pspiralife (Liquid Nails); track <b>Oni</b> en VA Reborn. <b>Festivales:</b> Earthdance RS, Flux Indoor.',
      de: '<b>Diego Brinker</b>, Südbrasilien. Definiert als ein akribisch konstruiertes Reich der Fantasie, das aus den Grenzen der Wahrnehmung selbst entsteht. Tiefe, rätselhafte, samtige und visionäre Soundscapes. <b>Auf Padang Records:</b> <b>Packet Loss</b> (11/2019), <b>Paracozm Redux</b> (06/2016); Remixe Hellquist (Northern Night) und Pspiralife (Liquid Nails); Track <b>Oni</b> auf VA Reborn. <b>Festivals:</b> Earthdance RS, Flux Indoor.',
      fr: '<b>Diego Brinker</b>, sud du Brésil. Défini comme un royaume imaginaire de fantaisie minutieusement construit, né dans les limites de la cognition elle-même. Soundscapes profonds, énigmatiques, veloutés et visionnaires. <b>Sur Padang Records :</b> <b>Packet Loss</b> (11/2019), <b>Paracozm Redux</b> (06/2016); remix Hellquist (Northern Night) et Pspiralife (Liquid Nails); morceau <b>Oni</b> sur VA Reborn. <b>Festivals :</b> Earthdance RS, Flux Indoor.',
      ja: '<b>Diego Brinker</b>、ブラジル南部出身。認知そのものの境界の中から立ち上がる、緻密に構築された幻想の王国として定義される。深く、謎めき、ベルベットのような視覚的サウンドスケープ。<b>Padang Records から：</b><b>Packet Loss</b>（2019年11月）、<b>Paracozm Redux</b>（2016年6月）；リミックス Hellquist（Northern Night）、Pspiralife（Liquid Nails）；VA Reborn に <b>Oni</b>。<b>フェス：</b>Earthdance RS、Flux Indoor。'
    },

    "Psydewise": {
      en: '<b>Sam Gamgee</b>, Garden Route, South Africa. "Music producer, merry prankster". Styles: Psytrance, Zenonesque, Dark Progressive. Debut <b>Dirty Wizards</b> — a dark and groovy tech-meets-progressive blend. EP <b>Mandelbrot Sequence</b> on Padang Records. Hanging Gardens (WIP) collab with Camps Elisis. Contact: psydewise@gmail.com.',
      es: '<b>Sam Gamgee</b>, Garden Route, Sudáfrica. "Music producer, merry prankster". Estilos: Psytrance, Zenonesque, Dark Progressive. Debut <b>Dirty Wizards</b> — blend dark y groovy de tech y progressive. EP <b>Mandelbrot Sequence</b> en Padang Records. Colab Hanging Gardens (WIP) con Camps Elisis. Contacto: psydewise@gmail.com.',
      de: '<b>Sam Gamgee</b>, Garden Route, Südafrika. "Music producer, merry prankster". Stile: Psytrance, Zenonesque, Dark Progressive. Debüt <b>Dirty Wizards</b> — düstere und groovige Tech-meets-Progressive-Mischung. EP <b>Mandelbrot Sequence</b> auf Padang Records. Hanging-Gardens-Kollab (WIP) mit Camps Elisis. Kontakt: psydewise@gmail.com.',
      fr: '<b>Sam Gamgee</b>, Garden Route, Afrique du Sud. « Music producer, merry prankster ». Styles : Psytrance, Zenonesque, Dark Progressive. Premier <b>Dirty Wizards</b> — mélange dark et groovy de tech et progressive. EP <b>Mandelbrot Sequence</b> sur Padang Records. Collab Hanging Gardens (WIP) avec Camps Elisis. Contact : psydewise@gmail.com.',
      ja: '<b>Sam Gamgee</b>、南アフリカ・ガーデンルート出身。「Music producer, merry prankster」。スタイル：Psytrance、Zenonesque、Dark Progressive。デビュー <b>Dirty Wizards</b> — ダークでグルーヴィーな tech ＋ progressive のブレンド。Padang Records から EP <b>Mandelbrot Sequence</b>。Camps Elisis と Hanging Gardens（制作中）でコラボ。連絡先: psydewise@gmail.com。'
    },"Rhabia": {
      en: '<b>Lena Rhabia Krenke</b>, Germany. DJ, singer, songwriter and producer — a boundless alchemist of sound and emotion. Grew up between punk, metal and rock, inspired by neo-soul, jazz, hip-hop and classical vocalists, fusing those roots into deep, unpredictable musical journeys. Sharing her sound internationally <b>since 2015</b>; represented Universal Tribe Records from 2019 and in <b>2024 joined Padang Records</b>. Her sets travel through <b>Psytech, Dark- & Bushprog, Zenonesque, Breaks, DnB</b> and deep, primal techno — always seeking that every emotion be felt. Psychedelic journeys fused with depths, textures and storytelling. Live performances may include microphone and voice in a hybrid setup. <b>Festivals:</b> Modem Festival (Croatia), Bucht der Träumer, Fusion, Hadra Trance, Antaris, Hive. Curated on Padang Records the <b>VA Nyctophilia</b> (02/2025), including the track <b>Amante Oscuro</b> with DMnT and Semilocybe. Contact: booking.rhabia@web.de.',
      es: '<b>Lena Rhabia Krenke</b>, Alemania. DJ, cantante, songwriter y productora — una boundless alchemist of sound and emotion. Creció entre punk, metal y rock, inspirada por neo-soul, jazz, hip-hop y vocalistas clásicas, fusionando esas raíces en viajes musicales profundos e impredecibles. Comparte su sonido internacionalmente <b>desde 2015</b>; representó a Universal Tribe Records desde 2019 y en <b>2024 se unió a Padang Records</b>. Sus sets transitan por <b>Psytech, Dark- & Bushprog, Zenonesque, Breaks, DnB</b> y techno profundo y primal — siempre buscando que cada emoción sea sentida. Viajes psicodélicos fundidos con profundidades, texturas y storytelling. Las presentaciones en vivo pueden incluir micrófono y voz en setup híbrido. <b>Festivales:</b> Modem Festival (Croacia), Bucht der Träumer, Fusion, Hadra Trance, Antaris, Hive. Curó en Padang Records la <b>VA Nyctophilia</b> (02/2025), incluyendo el track <b>Amante Oscuro</b> con DMnT y Semilocybe. Contacto: booking.rhabia@web.de.',
      de: '<b>Lena Rhabia Krenke</b>, Deutschland. DJ, Sängerin, Songwriterin und Produzentin — eine boundless alchemist of sound and emotion. Aufgewachsen zwischen Punk, Metal und Rock, inspiriert von Neo-Soul, Jazz, Hip-Hop und klassischen Vokalistinnen, verschmilzt sie diese Wurzeln zu tiefen, unvorhersehbaren musikalischen Reisen. Teilt ihren Sound international <b>seit 2015</b>; vertrat Universal Tribe Records ab 2019 und schloss sich <b>2024 Padang Records</b> an. Ihre Sets bewegen sich durch <b>Psytech, Dark- & Bushprog, Zenonesque, Breaks, DnB</b> und tiefen, primal techno — immer mit dem Ziel, dass jede Emotion gefühlt werde. Psychedelische Reisen, verschmolzen mit Tiefe, Texturen und Storytelling. Live-Auftritte können Mikrofon und Gesang im hybriden Setup einschließen. <b>Festivals:</b> Modem Festival (Kroatien), Bucht der Träumer, Fusion, Hadra Trance, Antaris, Hive. Kuratierte auf Padang Records die <b>VA Nyctophilia</b> (02/2025), einschließlich des Tracks <b>Amante Oscuro</b> mit DMnT und Semilocybe. Kontakt: booking.rhabia@web.de.',
      fr: '<b>Lena Rhabia Krenke</b>, Allemagne. DJ, chanteuse, songwriter et productrice — une boundless alchemist of sound and emotion. A grandi entre punk, metal et rock, inspirée par le neo-soul, le jazz, le hip-hop et les vocalistes classiques, fondant ces racines en voyages musicaux profonds et imprévisibles. Partage son son à l\'international <b>depuis 2015</b> ; représentait Universal Tribe Records à partir de 2019 et a rejoint <b>Padang Records en 2024</b>. Ses sets traversent <b>Psytech, Dark- & Bushprog, Zenonesque, Breaks, DnB</b> et techno profond et primal — cherchant toujours à ce que chaque émotion soit ressentie. Voyages psychédéliques fondus à des profondeurs, textures et storytelling. Les performances live peuvent intégrer micro et voix en setup hybride. <b>Festivals :</b> Modem Festival (Croatie), Bucht der Träumer, Fusion, Hadra Trance, Antaris, Hive. A curaté sur Padang Records la <b>VA Nyctophilia</b> (02/2025), incluant le morceau <b>Amante Oscuro</b> avec DMnT et Semilocybe. Contact : booking.rhabia@web.de.',
      ja: '<b>Lena Rhabia Krenke</b>、ドイツ出身。DJ／シンガー／ソングライター／プロデューサー — 音と感情の境界なきアルケミスト。パンク、メタル、ロックの中で育ち、ネオソウル、ジャズ、ヒップホップ、クラシックのヴォーカリストにインスパイアされ、それらのルーツを深く予測不能な音楽的ジャーニーへと融合する。<b>2015年から</b>サウンドを国際的にシェアし、2019年から Universal Tribe Records を代表、<b>2024年に Padang Records に加入</b>。彼女のセットは <b>Psytech、Dark- & Bushprog、Zenonesque、Breaks、DnB</b>、深く原始的なテクノを行き来する — 常にすべての感情が感じられることを目指して。深み、テクスチャ、ストーリーテリングと融合したサイケデリックなジャーニー。ライブ・パフォーマンスではマイクとヴォーカルをハイブリッド・セットアップで取り入れることもある。<b>フェス：</b>Modem Festival（クロアチア）、Bucht der Träumer、Fusion、Hadra Trance、Antaris、Hive。Padang Records で <b>VA Nyctophilia</b>（2025年2月）をキュレーション — DMnT と Semilocybe との <b>Amante Oscuro</b> を収録。連絡先: booking.rhabia@web.de。'
    },

    "Ritalin Child": {
      en: 'DJ/producer from Córdoba, Argentina. Hypnotic psychedelic trance, dark atmospheres, insane basslines. On Padang Records: <b>The Awakening EP</b>, <b>Attention Deficit</b> (VA Exogenesis), <b>Control This...</b> (VA Haunted Spectre 2) and <b>Blue Beam Project</b>. Maintains a Padang Records playlist on SoundCloud.',
      es: 'DJ/productor de Córdoba, Argentina. Trance psicodélico hipnótico, atmósferas oscuras, basslines insanos. En Padang Records: <b>The Awakening EP</b>, <b>Attention Deficit</b> (VA Exogenesis), <b>Control This...</b> (VA Haunted Spectre 2) y <b>Blue Beam Project</b>. Mantiene playlist Padang Records en SoundCloud.',
      de: 'DJ/Produzent aus Córdoba, Argentinien. Hypnotischer psychedelischer Trance, düstere Atmosphären, wahnsinnige Basslines. Auf Padang Records: <b>The Awakening EP</b>, <b>Attention Deficit</b> (VA Exogenesis), <b>Control This...</b> (VA Haunted Spectre 2) und <b>Blue Beam Project</b>. Pflegt eine Padang-Records-Playlist auf SoundCloud.',
      fr: 'DJ/producteur de Córdoba, Argentine. Trance psychédélique hypnotique, atmosphères sombres, basses délirantes. Sur Padang Records : <b>The Awakening EP</b>, <b>Attention Deficit</b> (VA Exogenesis), <b>Control This...</b> (VA Haunted Spectre 2) et <b>Blue Beam Project</b>. Tient une playlist Padang Records sur SoundCloud.',
      ja: 'アルゼンチン・コルドバ出身の DJ／プロデューサー。催眠的なサイケデリック・トランス、ダークなアトモスフィア、狂気じみたベースライン。Padang Records から：<b>The Awakening EP</b>、<b>Attention Deficit</b>（VA Exogenesis）、<b>Control This...</b>（VA Haunted Spectre 2）、<b>Blue Beam Project</b>。SoundCloud で Padang Records プレイリストを運営。'
    },"Rollercoaster": {
      en: '<b>Gabriel Gómez</b>, Chile — born in <b>Concepción in 1977</b> (cradle of Chilean rock). 15+ years producing electronic music. He discovered music during his university years when jazz was his passion; he enrolled in the jazz school of <b>Marlón Romero</b> and studied electric bass for years before moving into synthesizer-generated sounds and electronic beats, creating several projects alongside collaborations with major artists of the global electronic scene. <b>Aliases:</b> Rollercoaster / Paracoaster / Arcturians / Gao / Kilbee. Festival sets across <b>all 5 continents</b>: South America, North America, Europe, Asia, Oceania and Africa. <b>On Padang Records:</b> <b>Brake the Chains</b> (25/12/2024) — 3 tracks (New Beginning, Brake the Chains, Is Not Real) and the <b>Volcano</b> collab with Paracozm.',
      es: '<b>Gabriel Gómez</b>, Chile — nacido en <b>Concepción en 1977</b> (cuna del rock chileno). 15+ años produciendo electrónica. Descubrió la música en los años universitarios cuando el jazz era su pasión; entró en la escuela de jazz de <b>Marlón Romero</b> estudiando bajo eléctrico durante años, antes de migrar a sonidos generados por sintetizadores y beats electrónicos, creando varios proyectos junto a colaboraciones con grandes artistas de la escena electrónica mundial. <b>Alias:</b> Rollercoaster / Paracoaster / Arcturians / Gao / Kilbee. Sets en festivales por <b>todos los 5 continentes</b>: Sudamérica, Norteamérica, Europa, Asia, Oceanía y África. <b>En Padang Records:</b> <b>Brake the Chains</b> (25/12/2024) — 3 tracks (New Beginning, Brake the Chains, Is Not Real) y colab <b>Volcano</b> con Paracozm.',
      de: '<b>Gabriel Gómez</b>, Chile — geboren in <b>Concepción 1977</b> (Wiege des chilenischen Rock). 15+ Jahre elektronische Musikproduktion. Er entdeckte die Musik während seines Studiums, als Jazz seine Leidenschaft war; trat in die Jazz-Schule von <b>Marlón Romero</b> ein und studierte jahrelang E-Bass, bevor er zu synthesizer-generierten Klängen und elektronischen Beats wechselte und mehrere Projekte sowie Kollaborationen mit großen Künstlern der globalen elektronischen Szene schuf. <b>Aliase:</b> Rollercoaster / Paracoaster / Arcturians / Gao / Kilbee. Festival-Sets auf <b>allen 5 Kontinenten</b>: Südamerika, Nordamerika, Europa, Asien, Ozeanien und Afrika. <b>Auf Padang Records:</b> <b>Brake the Chains</b> (25.12.2024) — 3 Tracks (New Beginning, Brake the Chains, Is Not Real) und <b>Volcano</b>-Kollab mit Paracozm.',
      fr: '<b>Gabriel Gómez</b>, Chili — né à <b>Concepción en 1977</b> (berceau du rock chilien). 15+ ans de production de musique électronique. Il a découvert la musique pendant ses années universitaires, alors que le jazz était sa passion ; il a rejoint l\'école de jazz de <b>Marlón Romero</b> et étudié la basse électrique pendant des années avant de basculer vers les sons générés par synthétiseurs et les beats électroniques, créant plusieurs projets et collaborant avec de grands artistes de la scène électronique mondiale. <b>Alias :</b> Rollercoaster / Paracoaster / Arcturians / Gao / Kilbee. Sets de festival sur <b>les 5 continents</b> : Amérique du Sud, Amérique du Nord, Europe, Asie, Océanie et Afrique. <b>Sur Padang Records :</b> <b>Brake the Chains</b> (25/12/2024) — 3 morceaux (New Beginning, Brake the Chains, Is Not Real) et collab <b>Volcano</b> avec Paracozm.',
      ja: '<b>Gabriel Gómez</b>、チリ — <b>1977年にコンセプシオン</b>（チリ・ロックの揺りかご）で生まれる。15年以上にわたりエレクトロニック音楽を制作。大学時代にジャズに情熱を注ぐなかで音楽と出会い、<b>Marlón Romero</b> のジャズ・スクールに入学、数年間エレキベースを学んだのちシンセサイザー由来のサウンドとエレクトロニック・ビートへと移行。世界のエレクトロニックシーンを代表するアーティストたちとのコラボレーションとともに、いくつものプロジェクトを生み出してきた。<b>エイリアス：</b>Rollercoaster／Paracoaster／Arcturians／Gao／Kilbee。<b>5大陸全て</b>（南米、北米、ヨーロッパ、アジア、オセアニア、アフリカ）でフェスティバル・セットを披露。<b>Padang Records から：</b><b>Brake the Chains</b>（2024年12月25日） — 3トラック（New Beginning、Brake the Chains、Is Not Real）と Paracozm との <b>Volcano</b> コラボ。'
    },"Ronaldo Noctusense": {
      en: '<b>Ronaldo Lindote</b>, southern Bahia, Brazil. Active in the region\'s psytrance scene <b>since 2013</b>, DJ Noctusense has sculpted a distinctive sound rooted in the realms of <b>Dark Progressive</b>. His sets explore deep, swampy atmospheres woven with dense, rolling basslines — hypnotic journeys that invite the listener into altered states of perception. Strong focus on tension, groove and immersive sound design: Noctusense delivers carefully built narratives on the dancefloor. As a Padang Records compiler, he curated the <b>VA Haunted Spectre 1-4</b> series (2016-2024) — gathering tracks from friends around the world in a freaky fusion of psychedelic, experimental and avant-garde. Performances marked by depth, consistency and ritualistic flow — guiding the audience through deep frequencies and shadowy sonic landscapes. Contact: noctusense.dj@gmail.com.',
      es: '<b>Ronaldo Lindote</b>, sur de Bahía, Brasil. Activo en la escena psytrance de la región <b>desde 2013</b>, DJ Noctusense ha esculpido un sonido distintivo enraizado en los dominios del <b>Dark Progressive</b>. Sus sets exploran atmósferas profundas y pantanosas entrelazadas con basslines densas y rolantes — viajes hipnóticos que invitan al oyente a estados alterados de percepción. Fuerte foco en tensión, groove y sound design inmersivo: Noctusense entrega narrativas cuidadosamente construidas en la pista. Como compilador de Padang Records, curó la serie <b>VA Haunted Spectre 1-4</b> (2016-2024) — reuniendo tracks de amigos por todo el mundo en una freaky fusion de psicodélico, experimental y avant-garde. Performances marcadas por profundidad, consistencia y flujo ritualístico — guiando a la audiencia por frecuencias profundas y paisajes sónicos sombríos. Contacto: noctusense.dj@gmail.com.',
      de: '<b>Ronaldo Lindote</b>, südliches Bahia, Brasilien. Aktiv in der Psytrance-Szene der Region <b>seit 2013</b>, hat DJ Noctusense einen unverwechselbaren Sound geschaffen, der tief in den Reichen des <b>Dark Progressive</b> wurzelt. Seine Sets erforschen tiefe, sumpfige Atmosphären, verwoben mit dichten, rollenden Basslines — hypnotische Reisen, die den Hörer in veränderte Wahrnehmungszustände einladen. Starker Fokus auf Spannung, Groove und immersives Sound-Design: Noctusense liefert sorgfältig gebaute Narrative auf der Tanzfläche. Als Padang-Records-Compiler kuratierte er die Reihe <b>VA Haunted Spectre 1-4</b> (2016-2024) — Tracks von Freunden weltweit in einer freaky Fusion aus Psychedelisch, Experimentell und Avantgarde. Auftritte, die durch Tiefe, Konsistenz und ritualistischen Flow geprägt sind — und das Publikum durch tiefe Frequenzen und schattige Klanglandschaften führen. Kontakt: noctusense.dj@gmail.com.',
      fr: '<b>Ronaldo Lindote</b>, sud de Bahia, Brésil. Actif dans la scène psytrance de la région <b>depuis 2013</b>, DJ Noctusense a sculpté un son distinctif enraciné dans les domaines du <b>Dark Progressive</b>. Ses sets explorent des atmosphères profondes et marécageuses tissées de basslines denses et roulantes — voyages hypnotiques qui invitent l\'auditeur à des états altérés de perception. Forte attention à la tension, au groove et au sound design immersif : Noctusense livre des narratifs soigneusement construits sur la piste. En tant que compilateur de Padang Records, il a curaté la série <b>VA Haunted Spectre 1-4</b> (2016-2024) — rassemblant les morceaux d\'amis du monde entier dans une freaky fusion de psychédélique, expérimental et avant-garde. Performances marquées par la profondeur, la cohérence et le flux rituel — guidant le public à travers des fréquences profondes et des paysages sonores ombragés. Contact : noctusense.dj@gmail.com.',
      ja: '<b>Ronaldo Lindote</b>、ブラジル・バイーア南部出身。<b>2013年</b>からこの地域の psytrance シーンで活動する DJ Noctusense は、<b>Dark Progressive</b> の領域に根ざした独自のサウンドを彫り上げてきた。彼のセットは深く湿地のようなアトモスフィアと密で転がるベースラインを織り上げる — 知覚の変容状態へと聴く者を誘う催眠的なジャーニー。テンション、グルーヴ、没入的なサウンドデザインに強くフォーカス — Noctusense はダンスフロアで丁寧に構築されたナラティブを届ける。Padang Records のコンパイラーとして、<b>VA Haunted Spectre 1-4</b> シリーズ（2016-2024）をキュレーション — 世界中の友人たちの楽曲を集め、サイケデリック・実験的・アヴァンギャルドが入り混じる freaky なフュージョンへと仕立てた。パフォーマンスは深み、一貫性、儀式的なフローで彩られ — 深い周波数と影のサウンドスケープを通して観客を導く。連絡先: noctusense.dj@gmail.com。'
    },"Runehk": {
      en: '<b>Hernán Llanos</b>, born in <b>El Bolsón (Argentine Patagonia) in 1984</b>. Living in Buenos Aires since 2005, when he became interested in electronic music — self-taught early on in minimal and techno, he started mixing on pickups and software before enrolling in a production-specialised institute. In <b>2018</b> he launched the Runehk project: two techno/minimal EPs in 2020/21 (Beatcode Records) and two albums on Padang Records, the most recent in 2025. His distinctive style mixes psychedelia with techno nuances, powerful basslines and energetic, characterful leads. <b>First international performance: Arkana Festival 2025 (Peru)</b>; he also plays clubs and bars across Buenos Aires. <b>On Padang Records:</b> <b>Broken Mind (24bit)</b> album (12/2022 — Broken Mind, Dark Code, Space Explorer), <b>Revolution</b> and track <b>Dolor de Mazo</b> (Technomad II, 05/2025). Also known as Avantrash.',
      es: '<b>Hernán Llanos</b>, nacido en <b>El Bolsón (Patagonia Argentina) en 1984</b>. Vive en Buenos Aires desde 2005, cuando se interesó por la música electrónica — autodidacta inicial en minimal y techno, empezó mixando en pickups y softwares antes de entrar en un instituto especializado en producción. En <b>2018</b> lanzó el proyecto Runehk: dos EPs techno/minimal en 2020/21 (Beatcode Records) y dos álbumes en Padang Records, el más reciente en 2025. Estilo distintivo mezcla psicodelia con matices techno, basslines potentes y leads enérgicos y característicos. <b>Primera performance internacional: Arkana Festival 2025 (Perú)</b>; también toca en clubes y bares de Buenos Aires. <b>En Padang Records:</b> álbum <b>Broken Mind (24bit)</b> (12/2022 — Broken Mind, Dark Code, Space Explorer), <b>Revolution</b> y track <b>Dolor de Mazo</b> (Technomad II, 05/2025). También conocido como Avantrash.',
      de: '<b>Hernán Llanos</b>, geboren in <b>El Bolsón (argentinisches Patagonien) im Jahr 1984</b>. Lebt seit 2005 in Buenos Aires, wo er sich für elektronische Musik zu interessieren begann — autodidaktisch zunächst in Minimal und Techno, mischte er auf Pickups und Software, bevor er an einem auf Produktion spezialisierten Institut studierte. <b>2018</b> startete er das Projekt Runehk: zwei Techno-/Minimal-EPs 2020/21 (Beatcode Records) und zwei Alben auf Padang Records, das jüngste 2025. Sein unverwechselbarer Stil verbindet Psychedelia mit Techno-Nuancen, kraftvollen Basslines und energiegeladenen, charaktervollen Leads. <b>Erster internationaler Auftritt: Arkana Festival 2025 (Peru)</b>; er spielt außerdem in Clubs und Bars in Buenos Aires. <b>Auf Padang Records:</b> Album <b>Broken Mind (24bit)</b> (12/2022 — Broken Mind, Dark Code, Space Explorer), <b>Revolution</b> und Track <b>Dolor de Mazo</b> (Technomad II, 05/2025). Auch bekannt als Avantrash.',
      fr: '<b>Hernán Llanos</b>, né à <b>El Bolsón (Patagonie argentine) en 1984</b>. Vit à Buenos Aires depuis 2005, lorsqu\'il s\'est intéressé à la musique électronique — autodidacte au départ en minimal et techno, il a commencé à mixer sur pickups et logiciels avant d\'intégrer un institut spécialisé en production. En <b>2018</b>, il lance le projet Runehk : deux EPs techno/minimal en 2020/21 (Beatcode Records) et deux albums sur Padang Records, le plus récent en 2025. Son style distinctif mêle psychédélie et nuances techno, basslines puissantes et leads énergiques et caractérisés. <b>Première performance internationale : Arkana Festival 2025 (Pérou)</b> ; il joue aussi dans des clubs et bars de Buenos Aires. <b>Sur Padang Records :</b> album <b>Broken Mind (24bit)</b> (12/2022 — Broken Mind, Dark Code, Space Explorer), <b>Revolution</b> et morceau <b>Dolor de Mazo</b> (Technomad II, 05/2025). Aussi connu sous le nom d\'Avantrash.',
      ja: '<b>Hernán Llanos</b>、<b>1984年にアルゼンチン・パタゴニアのエル・ボルソンで生まれる</b>。2005年からブエノスアイレス在住、エレクトロニック・ミュージックに関心を持つようになる — はじめはミニマルとテクノを独学し、ピックアップとソフトウェアでミックスをはじめたのち、プロダクションに特化した専門学校に入学。<b>2018年</b>に Runehk プロジェクトを始動：2020／21年にテクノ／ミニマル EP 2作（Beatcode Records）、Padang Records からアルバム 2 作（最新は 2025 年）。サイケデリアにテクノのニュアンス、力強いベースライン、エネルギッシュで個性的なリードサウンドを織り交ぜる独自のスタイル。<b>初の国際公演：Arkana Festival 2025（ペルー）</b>。ブエノスアイレスのクラブやバーでもプレイ。<b>Padang Records から：</b>アルバム <b>Broken Mind (24bit)</b>（2022年12月 — Broken Mind、Dark Code、Space Explorer）、<b>Revolution</b>、楽曲 <b>Dolor de Mazo</b>（Technomad II、2025年5月）。Avantrash としても知られる。'
    },

    "Secular Bonzo": {
      en: '<b>Franco Schneider and Augusto Comoretto</b>, southern Brazil. Dark Progressive project created by two friends to explore the low frequencies of electronic music. Forest and Psytrance influences integrate technology with beats into a unique immersive sound. On Padang Records: album <b>Dual Nature</b> (09/2023). Contact: secularbonzo@gmail.com.',
      es: '<b>Franco Schneider y Augusto Comoretto</b>, sur de Brasil. Proyecto Dark Progressive creado por dos amigos para explorar las frecuencias graves de la electrónica. Influencias Forest y Psytrance integran tecnología con beats en un sonido inmersivo único. En Padang Records: álbum <b>Dual Nature</b> (09/2023). Contacto: secularbonzo@gmail.com.',
      de: '<b>Franco Schneider und Augusto Comoretto</b>, Südbrasilien. Dark-Progressive-Projekt zweier Freunde zur Erforschung der tiefen Frequenzen elektronischer Musik. Forest- und Psytrance-Einflüsse verschmelzen Technologie und Beats zu einem einzigartigen, immersiven Sound. Auf Padang Records: Album <b>Dual Nature</b> (09/2023). Kontakt: secularbonzo@gmail.com.',
      fr: '<b>Franco Schneider et Augusto Comoretto</b>, sud du Brésil. Projet Dark Progressive créé par deux amis pour explorer les fréquences graves de la musique électronique. Des influences Forest et Psytrance intègrent la technologie aux beats dans un son immersif unique. Sur Padang Records : album <b>Dual Nature</b> (09/2023). Contact : secularbonzo@gmail.com.',
      ja: '<b>Franco Schneider と Augusto Comoretto</b>、ブラジル南部。エレクトロニック音楽の低周波数帯を探求するために 2 人の友人が立ち上げた Dark Progressive プロジェクト。Forest と Psytrance の影響が技術とビートを融合させ、独自の没入的サウンドを生む。Padang Records からアルバム <b>Dual Nature</b>（2023年9月）。連絡先: secularbonzo@gmail.com。'
    },

    "Smokcid": {
      en: '<b>Themis Dirlis</b>, Greece. Explores dark and atmospheric realms through minimalist compositions emphasizing simplicity and depth. <b>Zenonesque</b> and Dark Progressive aesthetics — organic textures with modular synthesizers, immersive evolving soundscapes. Debut EP <b>SPIRAL FORM</b>. On Padang Records: <b>Phazer</b> (VA Exogenesis 2017), <b>Portal Space</b> and collaboration <b>Noctura</b> with Headweller (VA Nyctophilia). Contact: dirlisd@gmail.com.',
      es: '<b>Themis Dirlis</b>, Grecia. Explora dominios oscuros y atmosféricos a través de composiciones minimalistas que enfatizan simplicidad y profundidad. Estética <b>Zenonesque</b> y Dark Progressive — texturas orgánicas con sintetizadores modulares, paisajes sonoros inmersivos en evolución. EP debut <b>SPIRAL FORM</b>. En Padang Records: <b>Phazer</b> (VA Exogenesis 2017), <b>Portal Space</b> y colaboración <b>Noctura</b> con Headweller (VA Nyctophilia). Contacto: dirlisd@gmail.com.',
      de: '<b>Themis Dirlis</b>, Griechenland. Erforscht düstere und atmosphärische Sphären durch minimalistische Kompositionen, die Einfachheit und Tiefe betonen. <b>Zenonesque</b>- und Dark-Progressive-Ästhetik — organische Texturen mit modularen Synthesizern, immersive sich entwickelnde Klanglandschaften. Debüt-EP <b>SPIRAL FORM</b>. Auf Padang Records: <b>Phazer</b> (VA Exogenesis 2017), <b>Portal Space</b> und Kollaboration <b>Noctura</b> mit Headweller (VA Nyctophilia). Kontakt: dirlisd@gmail.com.',
      fr: '<b>Themis Dirlis</b>, Grèce. Explore les sphères sombres et atmosphériques à travers des compositions minimalistes mettant l\'accent sur la simplicité et la profondeur. Esthétique <b>Zenonesque</b> et Dark Progressive — textures organiques avec synthétiseurs modulaires, paysages sonores immersifs en évolution. EP de début <b>SPIRAL FORM</b>. Sur Padang Records : <b>Phazer</b> (VA Exogenesis 2017), <b>Portal Space</b> et collaboration <b>Noctura</b> avec Headweller (VA Nyctophilia). Contact : dirlisd@gmail.com.',
      ja: '<b>Themis Dirlis</b>、ギリシャ出身。シンプルさと深みを強調するミニマリスト的なコンポジションを通してダークでアトモスフェリックな領域を探求。<b>Zenonesque</b> と Dark Progressive の美学 — モジュラーシンセサイザーによるオーガニックなテクスチャと、没入的に進化するサウンドスケープ。デビュー EP <b>SPIRAL FORM</b>。Padang Records から：<b>Phazer</b>（VA Exogenesis 2017）、<b>Portal Space</b>、Headweller との共作 <b>Noctura</b>（VA Nyctophilia）。連絡先: dirlisd@gmail.com。'
    },

    "Stix": {
      en: '<b>Deepy Sidhu</b>, Winnipeg, Canada. "Colouring outside the lines of dark tech". Producer and DJ of dark electronic music — hypnotic fusion of psytrance, psytech, techno, house and bass. Curated <b>VA Yin and Yang Studio Gang</b> on Padang Records (16/01/2025) — a celebration of light/dark, chaos/harmony duality. Contact: sidhudeepy@gmail.com.',
      es: '<b>Deepy Sidhu</b>, Winnipeg, Canadá. "Colouring outside the lines of dark tech". Productora y DJ de electrónica dark — fusión hipnótica de psytrance, psytech, techno, house y bass. Curó en Padang Records la <b>VA Yin and Yang Studio Gang</b> (16/01/2025) — celebración de dualidad luz/sombra, caos/armonía. Contacto: sidhudeepy@gmail.com.',
      de: '<b>Deepy Sidhu</b>, Winnipeg, Kanada. "Colouring outside the lines of dark tech". Produzentin und DJ dunkler elektronischer Musik — hypnotische Fusion aus Psytrance, Psytech, Techno, House und Bass. Kuratierte auf Padang Records die <b>VA Yin and Yang Studio Gang</b> (16.01.2025) — eine Feier der Dualität Licht/Dunkel, Chaos/Harmonie. Kontakt: sidhudeepy@gmail.com.',
      fr: '<b>Deepy Sidhu</b>, Winnipeg, Canada. « Colouring outside the lines of dark tech ». Productrice et DJ d\\\'électronique dark — fusion hypnotique de psytrance, psytech, techno, house et bass. A curaté sur Padang Records la <b>VA Yin and Yang Studio Gang</b> (16/01/2025) — célébration de la dualité lumière/ombre, chaos/harmonie. Contact : sidhudeepy@gmail.com.',
      ja: '<b>Deepy Sidhu</b>、カナダ・ウィニペグ出身。「Colouring outside the lines of dark tech」。dark エレクトロニックのプロデューサー／DJ — psytrance、psytech、techno、house、bass の催眠的なフュージョン。Padang Records で <b>VA Yin and Yang Studio Gang</b>（2025年1月16日）をキュレーション — 光／闇、混沌／調和の二元性を祝う。連絡先: sidhudeepy@gmail.com。'
    },

    "Stopless": {
      en: '<b>Aldi Castori</b>, born in Mexico, lives in Pachuca. After 10 years in grunge/rock/indie bands on guitar, bass and drums, in 2009 he moved into IDM, experimental and psytrance. On Padang Records he released <b>Synchromisticism</b> and the track <b>Stone Cutters</b>. Collaborated with Jungle Haze on the <b>Technochtitlan EP</b> in 2018.',
      es: '<b>Aldi Castori</b>, nacido en México, vive en Pachuca. Tras 10 años en bandas de grunge/rock/indie tocando guitarra, bajo y batería, en 2009 migró a IDM, experimental y psytrance. En Padang Records lanzó <b>Synchromisticism</b> y el track <b>Stone Cutters</b>. Colaboró con Jungle Haze en el <b>Technochtitlan EP</b> en 2018.',
      de: '<b>Aldi Castori</b>, geboren in Mexiko, lebt in Pachuca. Nach 10 Jahren in Grunge-/Rock-/Indie-Bands an Gitarre, Bass und Schlagzeug wechselte er 2009 zu IDM, Experimental und Psytrance. Auf Padang Records veröffentlichte er <b>Synchromisticism</b> und den Track <b>Stone Cutters</b>. Kollaboration mit Jungle Haze auf der <b>Technochtitlan EP</b> 2018.',
      fr: '<b>Aldi Castori</b>, né au Mexique, vit à Pachuca. Après 10 ans dans des groupes grunge/rock/indie à la guitare, basse et batterie, il bascule en 2009 vers l\\\'IDM, l\\\'expérimental et le psytrance. Sur Padang Records il a sorti <b>Synchromisticism</b> et le morceau <b>Stone Cutters</b>. A collaboré avec Jungle Haze sur le <b>Technochtitlan EP</b> en 2018.',
      ja: '<b>Aldi Castori</b>、メキシコ生まれ、パチューカ在住。grunge／rock／indie バンドでギター、ベース、ドラムを 10 年プレイしたのち、2009年に IDM、実験的音楽、psytrance へ移行。Padang Records から <b>Synchromisticism</b> と楽曲 <b>Stone Cutters</b> をリリース。2018年に Jungle Haze と <b>Technochtitlan EP</b> でコラボ。'
    },

    "Sumerian Droids": {
      en: '<b>Pioneer of Dark Progressive</b> in Chile and worldwide, in the original Zenon style. Explores Swap Progressive, Minimalistic, Glitch, Techno and Psychedelic Progressive (120-142 BPM). Started as the duo Diego + Gabriel; today a solo project of <b>Gabriel (Josh Live, Cryptophonix)</b> from Santiago. On Padang Records: track <b>Brahmasutra</b>. <b>Festivals:</b> 3 Dimensions Festival (live set 2022).',
      es: '<b>Pionero del Dark Progressive</b> en Chile y el mundo, en el estilo original Zenon. Explora Swap Progressive, Minimalistic, Glitch, Techno y Psychedelic Progressive (120-142 BPM). Empezó como dúo Diego + Gabriel; hoy es proyecto solo de <b>Gabriel (Josh Live, Cryptophonix)</b> de Santiago. En Padang Records: track <b>Brahmasutra</b>. <b>Festivales:</b> 3 Dimensions Festival (live set 2022).',
      de: '<b>Pionier des Dark Progressive</b> in Chile und weltweit, im Original-Zenon-Stil. Erforscht Swap Progressive, Minimalistic, Glitch, Techno und Psychedelic Progressive (120-142 BPM). Begann als Duo Diego + Gabriel; heute ein Solo-Projekt von <b>Gabriel (Josh Live, Cryptophonix)</b> aus Santiago. Auf Padang Records: Track <b>Brahmasutra</b>. <b>Festivals:</b> 3 Dimensions Festival (Live-Set 2022).',
      fr: '<b>Pionnier du Dark Progressive</b> au Chili et dans le monde, dans le style original Zenon. Explore Swap Progressive, Minimalistic, Glitch, Techno et Psychedelic Progressive (120-142 BPM). Démarré en duo Diego + Gabriel; aujourd\'hui projet solo de <b>Gabriel (Josh Live, Cryptophonix)</b> de Santiago. Sur Padang Records : morceau <b>Brahmasutra</b>. <b>Festivals :</b> 3 Dimensions Festival (live set 2022).',
      ja: 'チリと世界における <b>Dark Progressive の先駆者</b>、オリジナルの Zenon スタイル。Swap Progressive、Minimalistic、Glitch、Forest、Techno、Psychedelic Progressive（120-142 BPM）を探求。Diego ＋ Gabriel のデュオとして始まり、現在はサンティアゴの <b>Gabriel（Josh Live、Cryptophonix）</b> のソロ・プロジェクト。Padang Records から楽曲 <b>Brahmasutra</b>。<b>フェス：</b>3 Dimensions Festival（2022年ライブセット）。'
    },"Sundenbock & Maddizin": {
      en: '<b>Florentin Böck</b> and <b>Mathis Schwoerer-Boehning</b>, Freiburg, Germany. A duo — the collaboration of two longtime friends driven by a shared passion for electronic music. They started with Techno and Minimal; the sound evolved toward deeper psychedelic influences. With a hardware-focused setup of synthesizers and effects, they sculpt a distinct fusion of analog warmth and electronic precision. Today S&M blend <b>Tech-Trance and Zenonesque elements</b>, exploring the space between Techno and Psy to create an immersive sonic experience. <b>On Padang Records:</b> <b>Flying Zoo</b> (02/2026), <b>Neurovers</b>, <b>Sonos Aureus</b> (live mix), <b>Salt & Suger</b> and <b>Synonym</b>. Contact: Flo.bock95@gmail.com.',
      es: '<b>Florentin Böck</b> y <b>Mathis Schwoerer-Boehning</b>, Friburgo, Alemania. Dúo — colaboración de dos amigos de toda la vida movidos por una pasión compartida por la música electrónica. Empezaron con Techno y Minimal; el sonido evolucionó hacia influencias psicodélicas más profundas. Con setup hardware-focused de sintetizadores y efectos, esculpen una fusión distinta de calor analógico y precisión electrónica. Hoy S&M mezcla <b>Tech-Trance y elementos Zenonesque</b>, explorando el espacio entre Techno y Psy para crear una experiencia sónica inmersiva. <b>En Padang Records:</b> <b>Flying Zoo</b> (02/2026), <b>Neurovers</b>, <b>Sonos Aureus</b> (live mix), <b>Salt & Suger</b> y <b>Synonym</b>. Contacto: Flo.bock95@gmail.com.',
      de: '<b>Florentin Böck</b> und <b>Mathis Schwoerer-Boehning</b>, Freiburg, Deutschland. Duo — die Zusammenarbeit zweier langjähriger Freunde, getrieben von einer gemeinsamen Leidenschaft für elektronische Musik. Sie begannen mit Techno und Minimal; der Sound entwickelte sich in Richtung tieferer psychedelischer Einflüsse. Mit einem hardware-fokussierten Setup aus Synthesizern und Effekten formen sie eine eigenständige Fusion aus analoger Wärme und elektronischer Präzision. Heute mischt S&M <b>Tech-Trance und Zenonesque-Elemente</b>, erkundet den Raum zwischen Techno und Psy und schafft so ein immersives Klangerlebnis. <b>Auf Padang Records:</b> <b>Flying Zoo</b> (02/2026), <b>Neurovers</b>, <b>Sonos Aureus</b> (Live-Mix), <b>Salt & Suger</b> und <b>Synonym</b>. Kontakt: Flo.bock95@gmail.com.',
      fr: '<b>Florentin Böck</b> et <b>Mathis Schwoerer-Boehning</b>, Fribourg, Allemagne. Un duo — collaboration de deux amis de longue date animés par une passion commune pour la musique électronique. Ils ont commencé avec le Techno et le Minimal ; le son a évolué vers des influences psychédéliques plus profondes. Avec un setup hardware-focused de synthétiseurs et d\'effets, ils sculptent une fusion distincte entre chaleur analogique et précision électronique. Aujourd\'hui S&M mêle <b>Tech-Trance et éléments Zenonesque</b>, explorant l\'espace entre Techno et Psy pour créer une expérience sonore immersive. <b>Sur Padang Records :</b> <b>Flying Zoo</b> (02/2026), <b>Neurovers</b>, <b>Sonos Aureus</b> (live mix), <b>Salt & Suger</b> et <b>Synonym</b>. Contact : Flo.bock95@gmail.com.',
      ja: '<b>Florentin Böck</b> と <b>Mathis Schwoerer-Boehning</b>、ドイツ・フライブルク出身。エレクトロニック・ミュージックへの共有された情熱に突き動かされた、長年の友人2人によるデュオ。Techno と Minimal から始まり、サウンドはより深いサイケデリックな影響へと進化していった。シンセサイザーとエフェクトを中心としたハードウェア重視のセットアップで、アナログの暖かさとエレクトロニックの精度が織りなす独自のフュージョンを彫り上げる。現在の S&M は <b>Tech-Trance と Zenonesque の要素</b>を融合し、Techno と Psy の間の空間を探求しながら没入的なサウンド体験を生み出す。<b>Padang Records から：</b><b>Flying Zoo</b>（2026年2月）、<b>Neurovers</b>、<b>Sonos Aureus</b>（ライブミックス）、<b>Salt & Suger</b>、<b>Synonym</b>。連絡先: Flo.bock95@gmail.com。'
    },

    "Symetric": {
      en: '<b>Symetric Live</b>, São Paulo, Brazil. Live act combining production precision with dancefloor energy. On Padang Records: <b>Alchemy Circle - RJ 2.0</b> remix and <b>Digital Forest</b> with Soulid (VA Padang × Noctusense). Performed live at PULSAR Festival 2023.',
      es: '<b>Symetric Live</b>, São Paulo, Brasil. Live act que combina precisión de producción con energía de pista. En Padang Records: remix <b>Alchemy Circle - RJ 2.0</b> y <b>Digital Forest</b> con Soulid (VA Padang × Noctusense). Live en PULSAR Festival 2023.',
      de: '<b>Symetric Live</b>, São Paulo, Brasilien. Live-Act, der Produktionspräzision mit Dancefloor-Energie verbindet. Auf Padang Records: Remix <b>Alchemy Circle - RJ 2.0</b> und <b>Digital Forest</b> mit Soulid (VA Padang × Noctusense). Live beim PULSAR Festival 2023.',
      fr: '<b>Symetric Live</b>, São Paulo, Brésil. Live act combinant précision de production et énergie de dancefloor. Sur Padang Records : remix <b>Alchemy Circle - RJ 2.0</b> et <b>Digital Forest</b> avec Soulid (VA Padang × Noctusense). Live au PULSAR Festival 2023.',
      ja: '<b>Symetric Live</b>、ブラジル・サンパウロ。プロダクションの精度とダンスフロアのエネルギーを融合させるライブアクト。Padang Records から：<b>Alchemy Circle - RJ 2.0</b> リミックスと、Soulid との <b>Digital Forest</b>（VA Padang × Noctusense）。PULSAR Festival 2023 でライブ。'
    },"Tekmall": {
      en: '<b>Vagner Donada</b>, Porto Alegre, southern Brazil. Tekmall is the name of the project founded in <b>2012</b>. Sets described as <b>deep Progressive Trance with a dark psychedelic touch</b> — influenced by the darker side of psychedelic trance, mixing his musical influences with the sci-fi genre. Tekmall evolved with a deep appreciation for low frequencies, intricate percussion and complex rhythms. Recognised for versatility, blending dark elements into hypnotic and playful atmospheres — captivating sets that carry strong, heavy intensity. Range from <b>135 to 144 BPM</b>, day or night. He navigates the realms of Dark Progressive Trance with a rare sense of mystery and discovery, eccentric basslines, unique musicality — the central drive is the search for innovation, grooves and rhythms that fully envelop a dancefloor with psychedelic music. <b>On Padang Records:</b> compiled and curated <b>VA Reborn: Echoes of the Forest</b> (25/11/2025), dedicated to the memory of his brother Leandro Donada. <b>Festivals:</b> Earthdance Festival 2025, Undervision Festival 2021, Arkana Festival 2025 (Sacred Valley of the Incas, Peru), Padang Records × Blacklite. Contact: tekmallmusic@gmail.com.',
      es: '<b>Vagner Donada</b>, Porto Alegre, sur de Brasil. Tekmall es el nombre del proyecto fundado en <b>2012</b>. Sets descritos como <b>Trance Progresivo profundo con toque psicodélico oscuro</b> — influenciado por el lado más sombrío del trance psicodélico, mezclando sus influencias musicales con el género de ciencia ficción. Tekmall evolucionó con gran aprecio por las frecuencias profundas, percusión intrincada y ritmos complejos. Reconocido por la versatilidad donde mezcla elementos de oscuridad, creando atmósfera hipnótica y lúdica — sets cautivantes que cargan intensidad fuerte y pesada. Rango de <b>135 a 144 BPM</b>, día o noche. Navega por los dominios del Dark Progressive Trance con una rara sensación de misterio y descubrimiento, basslines excéntricos, musicalidad única — la propuesta central es la búsqueda por innovación, grooves y ritmos que envuelvan por completo una pista con música psicodélica. <b>En Padang Records:</b> compiló y curó <b>VA Reborn: Echoes of the Forest</b> (25/11/2025), dedicada a la memoria de su hermano Leandro Donada. <b>Festivales:</b> Earthdance Festival 2025, Undervision Festival 2021, Arkana Festival 2025 (Valle Sagrado de los Incas, Perú), Padang Records × Blacklite. Contacto: tekmallmusic@gmail.com.',
      de: '<b>Vagner Donada</b>, Porto Alegre, Südbrasilien. Tekmall ist der Name des <b>2012</b> gegründeten Projekts. Sets, die als <b>tiefer Progressive Trance mit dunklem psychedelischem Touch</b> beschrieben werden — beeinflusst von der düstereren Seite des psychedelischen Trance, die seine musikalischen Einflüsse mit dem Sci-Fi-Genre verschmilzt. Tekmall entwickelte sich mit großer Wertschätzung für tiefe Frequenzen, vielschichtige Perkussion und komplexe Rhythmen. Bekannt für seine Vielseitigkeit, in der er dunkle Elemente in hypnotische und verspielte Atmosphären mischt — fesselnde Sets mit starker, schwerer Intensität. Bandbreite von <b>135 bis 144 BPM</b>, bei Tag oder Nacht. Er navigiert die Reiche des Dark Progressive Trance mit seltenem Sinn für Mysterium und Entdeckung, exzentrischen Basslines, einzigartiger Musikalität — der zentrale Antrieb ist die Suche nach Innovation, Grooves und Rhythmen, die eine Tanzfläche vollständig in psychedelische Musik hüllen. <b>Auf Padang Records:</b> kompiliert und kuratiert <b>VA Reborn: Echoes of the Forest</b> (25.11.2025), gewidmet dem Andenken seines Bruders Leandro Donada. <b>Festivals:</b> Earthdance Festival 2025, Undervision Festival 2021, Arkana Festival 2025 (Heiliges Tal der Inka, Peru), Padang Records × Blacklite. Kontakt: tekmallmusic@gmail.com.',
      fr: '<b>Vagner Donada</b>, Porto Alegre, sud du Brésil. Tekmall est le nom du projet fondé en <b>2012</b>. Sets décrits comme <b>Trance Progressive profond aux touches psychédéliques sombres</b> — influencé par le versant le plus sombre du trance psychédélique, mêlant ses influences musicales au genre science-fiction. Tekmall a évolué avec une grande appréciation des fréquences profondes, des percussions intriquées et des rythmes complexes. Reconnu pour sa polyvalence, mélangeant des éléments d\'obscurité dans des atmosphères hypnotiques et ludiques — sets captivants à l\'intensité forte et lourde. Plage de <b>135 à 144 BPM</b>, jour comme nuit. Il navigue dans les domaines du Dark Progressive Trance avec un sens rare du mystère et de la découverte, basslines excentriques, musicalité unique — le moteur central est la recherche d\'innovation, de grooves et de rythmes qui enveloppent totalement une piste avec la musique psychédélique. <b>Sur Padang Records :</b> a compilé et curaté <b>VA Reborn: Echoes of the Forest</b> (25/11/2025), dédié à la mémoire de son frère Leandro Donada. <b>Festivals :</b> Earthdance Festival 2025, Undervision Festival 2021, Arkana Festival 2025 (Vallée Sacrée des Incas, Pérou), Padang Records × Blacklite. Contact : tekmallmusic@gmail.com.',
      ja: '<b>Vagner Donada</b>、ブラジル南部・ポルト・アレグレ出身。Tekmall は <b>2012年</b>に設立されたプロジェクトの名前。<b>ダーク・サイケデリックなタッチを持つディープな Progressive Trance</b> と評されるセット — サイケデリック・トランスのより暗い側面に影響を受け、彼の音楽的影響を SF ジャンルとブレンドする。Tekmall は深い周波数帯、複雑なパーカッション、入り組んだリズムへの深い愛とともに進化してきた。多才さで知られ、ダークな要素を催眠的でプレイフルなアトモスフィアに溶け込ませる — 強く重いインテンシティを湛える魅惑的なセット。<b>135 から 144 BPM</b>、昼でも夜でも対応。Dark Progressive Trance の領域を稀有な神秘と発見の感覚、エクセントリックなベースライン、独自のミュージカリティで航行する — 中心にあるのは、サイケデリック音楽でダンスフロアを完全に包み込むための革新、グルーヴ、リズムの探求。<b>Padang Records から：</b><b>VA Reborn: Echoes of the Forest</b>（2025年11月25日）をコンパイル／キュレーション — 弟 Leandro Donada の追悼に捧げる。<b>フェス：</b>Earthdance Festival 2025、Undervision Festival 2021、Arkana Festival 2025（インカ聖なる谷、ペルー）、Padang Records × Blacklite。連絡先: tekmallmusic@gmail.com。'
    },"Tenebra": {
      en: '<b>Britt Rodrigues</b>, Brazil. Moving between <b>Psytech and Dark Progressive</b>, Tenebra leads the audience through a sonic journey marked by deep grooves, hypnotic textures and dense atmospheres. Every set is an experience that balances the dark and the seductive, rocking body and mind in a dance that crosses the bright and the obscure. Currently DJ at Padang Records, she presents an intense and engaging sonic identity — each track is a carefully built journey that explores the shadows without ever losing the beat, in a subtle dance between light and darkness. Featured in the set <b>Tekmall b2b Tenebra @ Padang Records × Blacklite</b> (03/2026). Contact: brittproducer@gmail.com.',
      es: '<b>Britt Rodrigues</b>, Brasil. Transitando entre <b>Psytech y Dark Progressive</b>, Tenebra conduce al público por un viaje sónico marcado por grooves profundos, texturas hipnóticas y atmósferas densas. Cada set es una experiencia que equilibra lo sombrío y lo seductor, meciendo cuerpo y mente en una danza que atraviesa lo claro y lo oscuro. Actualmente DJ de Padang Records, presenta una identidad sónica intensa y envolvente — cada track es un viaje cuidadosamente construido que explora las sombras sin nunca perder el ritmo, en una danza sutil entre luz y oscuridad. Apareció en el set <b>Tekmall b2b Tenebra @ Padang Records × Blacklite</b> (03/2026). Contacto: brittproducer@gmail.com.',
      de: '<b>Britt Rodrigues</b>, Brasilien. Zwischen <b>Psytech und Dark Progressive</b> changierend, führt Tenebra das Publikum durch eine klangliche Reise, geprägt von tiefen Grooves, hypnotischen Texturen und dichten Atmosphären. Jedes Set ist eine Erfahrung, die das Düstere und das Verführerische in Balance hält und Körper und Geist in einem Tanz wiegt, der das Helle und das Dunkle durchquert. Aktuell DJ bei Padang Records, präsentiert sie eine intensive und einnehmende klangliche Identität — jeder Track ist eine sorgfältig gebaute Reise, die die Schatten erforscht, ohne je den Beat zu verlieren, in einem subtilen Tanz zwischen Licht und Dunkelheit. Zu hören im Set <b>Tekmall b2b Tenebra @ Padang Records × Blacklite</b> (03/2026). Kontakt: brittproducer@gmail.com.',
      fr: '<b>Britt Rodrigues</b>, Brésil. Naviguant entre <b>Psytech et Dark Progressive</b>, Tenebra conduit le public à travers un voyage sonore marqué par des grooves profonds, des textures hypnotiques et des atmosphères denses. Chaque set est une expérience qui équilibre le sombre et le séduisant, berçant corps et esprit dans une danse qui traverse le clair et l\'obscur. Actuellement DJ pour Padang Records, elle présente une identité sonore intense et enveloppante — chaque morceau est un voyage soigneusement construit qui explore les ombres sans jamais perdre le tempo, dans une danse subtile entre lumière et obscurité. Apparue dans le set <b>Tekmall b2b Tenebra @ Padang Records × Blacklite</b> (03/2026). Contact : brittproducer@gmail.com.',
      ja: '<b>Britt Rodrigues</b>、ブラジル。<b>Psytech と Dark Progressive</b> の間を行き交いながら、Tenebra は深いグルーヴ、催眠的なテクスチャ、濃密なアトモスフィアに彩られたサウンドジャーニーへとオーディエンスを導く。各セットは闇と誘惑を絶妙に均衡させる体験 — 明と暗を横切るダンスで身体と精神を揺らす。現在 Padang Records の DJ として、強烈で心を引き込むサウンドのアイデンティティを提示する — 各トラックは丁寧に構築されたジャーニーであり、ビートを決して見失わずに影を探求し、光と闇の繊細なダンスを描き出す。<b>Tekmall b2b Tenebra @ Padang Records × Blacklite</b>（2026年3月）のセットに登場。連絡先: brittproducer@gmail.com。'
    },"Tystix": {
      en: '<b>Tyler Archer</b>, originally from the Garden Route, South Africa · now in Antwerp, Belgium. Producer focused on the constantly evolving psychedelic sound — looking to bring cutting-edge futuristic sound design and nocturnal soundscapes. With over <b>12 years of experience</b>, TyStix has sculpted a unique sound in the realm of <b>dark progressive</b>. His captivating performances have gone through numerous festivals: <b>Origin (South Africa), Modem Teaser Brussels (Belgium), BomShankar Prod (Belgium), Vortex (South Africa), Bucht der Träumer 2025</b>, among others — performances that transcend borders, leaving an indelible mark on diverse audiences. From a young age he was fascinated by the experimental and psychedelic music heard in the local trance scene; after learning to beat match and mix his main influences, in late <b>2012</b> he decided to start producing. <b>On Padang Records:</b> <b>Signals EP</b> (02/2026). Side projects: Ocular Scope, Trogon, Gnosis. Contact: Scopepsytechno@gmail.com.',
      es: '<b>Tyler Archer</b>, originalmente de Garden Route, sur de África · ahora en Amberes, Bélgica. Productor enfocado en el sonido psicodélico en constante evolución — busca traer sound design futurista de vanguardia y soundscapes nocturnos. Con más de <b>12 años de experiencia</b>, TyStix ha esculpido un sonido único en el reino del <b>dark progressive</b>. Sus performances cautivantes pasaron por innumerables festivales: <b>Origin (Sudáfrica), Modem Teaser Brussels (Bélgica), BomShankar Prod (Bélgica), Vortex (Sudáfrica), Bucht der Träumer 2025</b>, entre otros — performances que trascienden fronteras, dejando huella indeleble en audiencias diversas. Desde joven se fascinó con la música experimental y psicodélica escuchada en la escena trance local; tras aprender a beat match y mezclar sus principales influencias, a finales de <b>2012</b> decidió empezar a producir. <b>En Padang Records:</b> <b>Signals EP</b> (02/2026). Side projects: Ocular Scope, Trogon, Gnosis. Contacto: Scopepsytechno@gmail.com.',
      de: '<b>Tyler Archer</b>, ursprünglich aus der Garden Route, Südafrika · jetzt in Antwerpen, Belgien. Produzent mit Fokus auf einen sich ständig wandelnden psychedelischen Sound — er will modernstes futuristisches Sound Design und nächtliche Soundscapes vorantreiben. Mit über <b>12 Jahren Erfahrung</b> hat TyStix einen einzigartigen Sound im Bereich <b>Dark Progressive</b> geformt. Seine fesselnden Auftritte führten ihn über zahlreiche Festivals: <b>Origin (Südafrika), Modem Teaser Brüssel (Belgien), BomShankar Prod (Belgien), Vortex (Südafrika), Bucht der Träumer 2025</b>, unter anderen — Auftritte, die Grenzen überschreiten und bei vielfältigen Publika unauslöschliche Spuren hinterlassen. Von jung an faszinierte ihn die experimentelle und psychedelische Musik in der lokalen Trance-Szene; nachdem er Beat Matching und das Mischen seiner Haupteinflüsse gelernt hatte, beschloss er Ende <b>2012</b>, mit der Produktion zu beginnen. <b>Auf Padang Records:</b> <b>Signals EP</b> (02/2026). Side-Projects: Ocular Scope, Trogon, Gnosis. Kontakt: Scopepsytechno@gmail.com.',
      fr: '<b>Tyler Archer</b>, originaire de Garden Route, Afrique du Sud · désormais à Anvers, Belgique. Producteur centré sur le son psychédélique en évolution constante — il cherche à apporter un sound design futuriste à la pointe et des soundscapes nocturnes. Avec plus de <b>12 ans d\'expérience</b>, TyStix a sculpté un son unique dans le domaine du <b>dark progressive</b>. Ses performances captivantes l\'ont mené à de nombreux festivals : <b>Origin (Afrique du Sud), Modem Teaser Brussels (Belgique), BomShankar Prod (Belgique), Vortex (Afrique du Sud), Bucht der Träumer 2025</b>, parmi d\'autres — des prestations qui transcendent les frontières et laissent une marque indélébile sur des publics divers. Dès son plus jeune âge, il fut fasciné par la musique expérimentale et psychédélique entendue dans la scène trance locale ; après avoir appris à beat match et à mixer ses principales influences, fin <b>2012</b>, il décide de commencer à produire. <b>Sur Padang Records :</b> <b>Signals EP</b> (02/2026). Side projects : Ocular Scope, Trogon, Gnosis. Contact : Scopepsytechno@gmail.com.',
      ja: '<b>Tyler Archer</b>、南アフリカ・ガーデンルート出身・現在ベルギー・アントワープ拠点。常に進化し続けるサイケデリックサウンドにフォーカスするプロデューサー — 最先端のフューチャリスティックなサウンドデザインと夜のサウンドスケープをもたらすことを目指す。<b>12年以上の経験</b>を持ち、TyStix は <b>dark progressive</b> の領域で独自のサウンドを彫り上げてきた。その魅惑的なパフォーマンスは数多くのフェスを巡ってきた：<b>Origin（南アフリカ）、Modem Teaser Brussels（ベルギー）、BomShankar Prod（ベルギー）、Vortex（南アフリカ）、Bucht der Träumer 2025</b> など — 国境を越え、多様なオーディエンスに消えない痕跡を残すパフォーマンス。幼い頃から地元のトランスシーンで聴いた実験的・サイケデリックな音楽に魅了され、ビートマッチとミキシングを学んだのち、<b>2012年</b>末に制作を始めることを決意。<b>Padang Records から：</b><b>Signals EP</b>（2026年2月）。サイドプロジェクト：Ocular Scope、Trogon、Gnosis。連絡先: Scopepsytechno@gmail.com。'
    },

    "Vorg": {
      en: '<b>Robson Morche</b>, Brazil. <b>Resident artist of Padang Records</b>. Psytrance, Dark Progressive and Zenonesque. "Project created and experimented by Robson Morche, building his own mental reconstruction over the years." <b>On Padang Records:</b> <b>QUBE EP</b> with Paracozm (2023), <b>Echoes EP</b> (2022), <b>Cyber Soul: Day</b> and <b>Cyber Soul: Night</b> (2025), track <b>Undercity</b> on Nyctophilia II (2026), Paracozm — Framed remix, Dienstmann vs Vorg — Fractal Dimensions. <b>Festivals:</b> Earthdance (Padang Lab Series EP.18), Ecotribe Festival, Merry XMAS Padang 2017.',
      es: '<b>Robson Morche</b>, Brasil. <b>Artista residente de Padang Records</b>. Psytrance, Dark Progressive y Zenonesque. "Proyecto creado y experimentado por Robson Morche, construyendo su propia reconstrucción mental a lo largo de los años." <b>En Padang Records:</b> <b>QUBE EP</b> con Paracozm (2023), <b>Echoes EP</b> (2022), <b>Cyber Soul: Day</b> y <b>Cyber Soul: Night</b> (2025), track <b>Undercity</b> en Nyctophilia II (2026), remix Paracozm — Framed, Dienstmann vs Vorg — Fractal Dimensions. <b>Festivales:</b> Earthdance (Padang Lab Series EP.18), Ecotribe Festival, Merry XMAS Padang 2017.',
      de: '<b>Robson Morche</b>, Brasilien. <b>Resident-Artist von Padang Records</b>. Psytrance, Dark Progressive und Zenonesque. "Projekt von Robson Morche kreiert und erprobt, der über die Jahre seine eigene mentale Rekonstruktion baut." <b>Auf Padang Records:</b> <b>QUBE EP</b> mit Paracozm (2023), <b>Echoes EP</b> (2022), <b>Cyber Soul: Day</b> und <b>Cyber Soul: Night</b> (2025), Track <b>Undercity</b> auf Nyctophilia II (2026), Paracozm — Framed Remix, Dienstmann vs Vorg — Fractal Dimensions. <b>Festivals:</b> Earthdance (Padang Lab Series EP.18), Ecotribe Festival, Merry XMAS Padang 2017.',
      fr: '<b>Robson Morche</b>, Brésil. <b>Artiste résident de Padang Records</b>. Psytrance, Dark Progressive et Zenonesque. « Projet créé et expérimenté par Robson Morche, construisant sa propre reconstruction mentale au fil des années. » <b>Sur Padang Records :</b> <b>QUBE EP</b> avec Paracozm (2023), <b>Echoes EP</b> (2022), <b>Cyber Soul: Day</b> et <b>Cyber Soul: Night</b> (2025), morceau <b>Undercity</b> sur Nyctophilia II (2026), remix Paracozm — Framed, Dienstmann vs Vorg — Fractal Dimensions. <b>Festivals :</b> Earthdance (Padang Lab Series EP.18), Ecotribe Festival, Merry XMAS Padang 2017.',
      ja: '<b>Robson Morche</b>、ブラジル。<b>Padang Records レジデント・アーティスト</b>。Psytrance、Dark Progressive、Zenonesque。「Robson Morche によって創られ実験されたプロジェクトで、長年にわたり自身のメンタルな再構築を組み立てている」。<b>Padang Records から：</b>Paracozm との <b>QUBE EP</b>（2023）、<b>Echoes EP</b>（2022）、<b>Cyber Soul: Day</b> と <b>Cyber Soul: Night</b>（2025）、Nyctophilia II の <b>Undercity</b>（2026）、Paracozm — Framed リミックス、Dienstmann vs Vorg — Fractal Dimensions。<b>フェス：</b>Earthdance（Padang Lab Series EP.18）、Ecotribe Festival、Merry XMAS Padang 2017。'
    },

    "Yazata": {
      en: '<b>YAZATA</b>. "Born with rhythm in her soul" — her journey began on the dance floor as a passionate dancer and lifelong music lover. In 2024 she stepped behind the decks to craft her own sonic journeys: a unique blend of haunting melodies, deep basslines and immersive atmospheres. Part of Padang Records — delivered <b>Padang Lab Series EP.14</b> (New Year Mix, 12/2024) and <b>YAYSG</b> Album Mix compiled by Stix.',
      es: '<b>YAZATA</b>. "Born with rhythm in her soul" — su viaje comenzó en la pista como bailarina apasionada y amante de la música. En 2024 dio el paso detrás de los decks para crear sus propios viajes sónicos: blend único de melodías inquietantes, basslines profundos y atmósferas inmersivas. Integra Padang Records — presentó <b>Padang Lab Series EP.14</b> (New Year Mix, 12/2024) y <b>YAYSG</b> Album Mix compilado por Stix.',
      de: '<b>YAZATA</b>. "Born with rhythm in her soul" — ihre Reise begann auf der Tanzfläche als leidenschaftliche Tänzerin und lebenslange Musikliebhaberin. 2024 trat sie hinter die Decks, um ihre eigenen klanglichen Reisen zu gestalten: eine einzigartige Mischung aus haunting Melodien, tiefen Basslines und immersiven Atmosphären. Teil von Padang Records — lieferte <b>Padang Lab Series EP.14</b> (New Year Mix, 12/2024) und <b>YAYSG</b> Album Mix, kuratiert von Stix.',
      fr: '<b>YAZATA</b>. « Born with rhythm in her soul » — son voyage a commencé sur la piste, danseuse passionnée et amoureuse de la musique. En 2024 elle est passée derrière les platines pour façonner ses propres voyages sonores : un mélange unique de mélodies hantées, de basslines profondes et d\'atmosphères immersives. Intègre Padang Records — a livré <b>Padang Lab Series EP.14</b> (New Year Mix, 12/2024) et <b>YAYSG</b> Album Mix compilé par Stix.',
      ja: '<b>YAZATA</b>。「Born with rhythm in her soul」 — 彼女の旅は、情熱的なダンサーであり生涯の音楽愛好家として、ダンスフロアから始まった。2024年にデッキの後ろに立ち、自身の音の旅を紡ぎ始める：哀愁あるメロディ、深いベースライン、没入感のあるアトモスフィアのユニークなブレンド。Padang Records の一員 — <b>Padang Lab Series EP.14</b>（New Year Mix、2024年12月）を担当し、Stix がコンパイルした <b>YAYSG</b> Album Mix にも参加。'
    },
    "Con Fetti": {
      en: '<b>Con Fetti</b>, Munich, Germany. DJ/producer with a strong presence in the European underground and deep connection to Latin America. Plays regularly at <b>Bahnwärter Thiel</b>, <b>Zur Gruam</b>, <b>Unter Deck</b> and Munich clubs. <b>Festivals:</b> <b>Universo Paralelo</b> (Brazil, NYE 22/23 and 24), <b>Arkana Festival</b> (Peru, with Mallki — 2022, 2023, 2024), <b>Modem</b>, <b>Atman</b>, <b>Trikaya</b>, <b>Burning Beach</b>, <b>Cosmovision Tulum</b>, <b>Daaya Festival</b> (MX), <b>Mitoteliztli</b>, <b>Foresterra</b> (HR), <b>Sunrice</b>, <b>Arcadia</b> (PT). <b>B2B with Mallki</b> at LA Cultural Barcelona (2024) and Naked Zipolite (Mexico, 2023). 1,149 followers on SoundCloud, 25+ sets published. Instagram: <b>@con__fetti</b>.',
      es: '<b>Con Fetti</b>, Múnich, Alemania. DJ/productor con fuerte presencia en la escena underground europea y profunda conexión con Latinoamérica. Toca regularmente en <b>Bahnwärter Thiel</b>, <b>Zur Gruam</b>, <b>Unter Deck</b> y clubs de Múnich. <b>Festivales:</b> <b>Universo Paralelo</b> (Brasil, NYE 22/23 y 24), <b>Arkana Festival</b> (Perú, con Mallki — 2022, 2023, 2024), <b>Modem</b>, <b>Atman</b>, <b>Trikaya</b>, <b>Burning Beach</b>, <b>Cosmovision Tulum</b>, <b>Daaya Festival</b> (MX), <b>Mitoteliztli</b>, <b>Foresterra</b> (HR), <b>Sunrice</b>, <b>Arcadia</b> (PT). <b>B2B con Mallki</b> en LA Cultural Barcelona (2024) y Naked Zipolite (México, 2023). 1.149 seguidores en SoundCloud, 25+ sets publicados. Instagram: <b>@con__fetti</b>.',
      de: '<b>Con Fetti</b>, München, Deutschland. DJ/Produzent mit starker Präsenz in der europäischen Underground-Szene und tiefer Verbindung zu Lateinamerika. Spielt regelmäßig im <b>Bahnwärter Thiel</b>, <b>Zur Gruam</b>, <b>Unter Deck</b> und Münchner Clubs. <b>Festivals:</b> <b>Universo Paralelo</b> (Brasilien, NYE 22/23 und 24), <b>Arkana Festival</b> (Peru, mit Mallki — 2022, 2023, 2024), <b>Modem</b>, <b>Atman</b>, <b>Trikaya</b>, <b>Burning Beach</b>, <b>Cosmovision Tulum</b>, <b>Daaya Festival</b> (MX), <b>Mitoteliztli</b>, <b>Foresterra</b> (HR), <b>Sunrice</b>, <b>Arcadia</b> (PT). <b>B2B mit Mallki</b> im LA Cultural Barcelona (2024) und Naked Zipolite (Mexiko, 2023). 1.149 SoundCloud-Follower, 25+ Sets veröffentlicht. Instagram: <b>@con__fetti</b>.',
      fr: '<b>Con Fetti</b>, Munich, Allemagne. DJ/producteur avec une forte présence dans la scène underground européenne et une profonde connexion avec l\'Amérique latine. Joue régulièrement au <b>Bahnwärter Thiel</b>, <b>Zur Gruam</b>, <b>Unter Deck</b> et clubs de Munich. <b>Festivals :</b> <b>Universo Paralelo</b> (Brésil, NYE 22/23 et 24), <b>Arkana Festival</b> (Pérou, avec Mallki — 2022, 2023, 2024), <b>Modem</b>, <b>Atman</b>, <b>Trikaya</b>, <b>Burning Beach</b>, <b>Cosmovision Tulum</b>, <b>Daaya Festival</b> (MX), <b>Mitoteliztli</b>, <b>Foresterra</b> (HR), <b>Sunrice</b>, <b>Arcadia</b> (PT). <b>B2B avec Mallki</b> à LA Cultural Barcelone (2024) et Naked Zipolite (Mexique, 2023). 1 149 followers sur SoundCloud, 25+ sets publiés. Instagram : <b>@con__fetti</b>.',
      ja: '<b>Con Fetti</b>、ドイツ・ミュンヘン。ヨーロッパのアンダーグラウンドに強い存在感を持ち、ラテンアメリカと深いつながりを持つ DJ／プロデューサー。<b>Bahnwärter Thiel</b>、<b>Zur Gruam</b>、<b>Unter Deck</b> などミュンヘンのクラブで定期的に出演。<b>フェス：</b><b>Universo Paralelo</b>（ブラジル、NYE 22/23 および 24）、<b>Arkana Festival</b>（ペルー、Mallki と共に 2022、2023、2024）、<b>Modem</b>、<b>Atman</b>、<b>Trikaya</b>、<b>Burning Beach</b>、<b>Cosmovision Tulum</b>、<b>Daaya Festival</b>（MX）、<b>Mitoteliztli</b>、<b>Foresterra</b>（HR）、<b>Sunrice</b>、<b>Arcadia</b>（PT）。LA Cultural バルセロナ（2024）と Naked Zipolite（メキシコ、2023）で <b>Mallki との B2B</b>。SoundCloud フォロワー1,149人、25セット以上公開。Instagram：<b>@con__fetti</b>。'
    },
    "Fabinho": {
      en: '<b>Fábio Kirch</b>, Vale Real, Rio Grande do Sul (Brazil). DJ from the <b>Padang Records</b> family. Has been honing his mixing techniques aiming to bring a unique set to each performance, with coherence inside the proposal of every line-up. Moves through BPMs between <b>140 and 148</b>, guiding the floor through transitional textures toward a more frenetic rhythm. <b>On Padang Records:</b> presented <b>Padang Lab Series EP.15</b> (01/2025) as an exclusive set. SoundCloud work includes <b>Psychedelic Techno Vision</b> (01/2025) and <b>Mind in Transition</b> (02/2018).',
      es: '<b>Fábio Kirch</b>, Vale Real, Rio Grande do Sul (Brasil). DJ de la familia <b>Padang Records</b>. Viene perfeccionando sus técnicas de mezcla con el objetivo de traer un set único a cada presentación, con coherencia dentro de la propuesta de cada line-up. Transita por BPMs entre <b>140 y 148</b>, conduciendo a la pista por ambientes y elementos de transición hacia un ritmo más frenético. <b>En Padang Records:</b> presentó la <b>Padang Lab Series EP.15</b> (01/2025) en set exclusivo. Trabajos en SoundCloud incluyen <b>Psychedelic Techno Vision</b> (01/2025) y <b>Mind in Transition</b> (02/2018).',
      de: '<b>Fábio Kirch</b>, Vale Real, Rio Grande do Sul (Brasilien). DJ aus der <b>Padang Records</b>-Familie. Verfeinert seine Mixing-Techniken mit dem Ziel, bei jedem Auftritt einen einzigartigen Set zu liefern, mit Kohärenz innerhalb des Line-up-Konzepts. Bewegt sich durch BPMs zwischen <b>140 und 148</b>, führt den Floor durch Übergangstexturen zu einem frenetischeren Rhythmus. <b>Auf Padang Records:</b> präsentierte die <b>Padang Lab Series EP.15</b> (01/2025) als exklusiver Set. SoundCloud-Arbeiten umfassen <b>Psychedelic Techno Vision</b> (01/2025) und <b>Mind in Transition</b> (02/2018).',
      fr: '<b>Fábio Kirch</b>, Vale Real, Rio Grande do Sul (Brésil). DJ de la famille <b>Padang Records</b>. Affine ses techniques de mixage visant à apporter un set unique à chaque performance, avec cohérence dans la proposition de chaque line-up. Évolue entre des BPMs de <b>140 à 148</b>, guidant le dancefloor à travers des textures de transition vers un rythme plus frénétique. <b>Sur Padang Records :</b> a présenté la <b>Padang Lab Series EP.15</b> (01/2025) en set exclusif. Travaux SoundCloud incluent <b>Psychedelic Techno Vision</b> (01/2025) et <b>Mind in Transition</b> (02/2018).',
      ja: '<b>Fábio Kirch</b>、ブラジル・ヴァレ・ヘアル（リオ・グランデ・ド・スル）。<b>Padang Records</b> ファミリーの DJ。ラインアップの提案に沿いつつ毎回ユニークなセットを届けるため、ミキシング技術を磨いている。<b>140〜148 BPM</b> を往復し、フロアを変化に富んだ質感から熱狂的なリズムへと導く。<b>Padang Records から：</b><b>Padang Lab Series EP.15</b>（2025年1月）を独占セットとして披露。SoundCloud には <b>Psychedelic Techno Vision</b>（2025年1月）、<b>Mind in Transition</b>（2018年2月）など。'
    },
    "Psypox": {
      en: '<i>Note: SoundCloud profile not yet confirmed.</i> The soundcloud.com/psypox profile is an empty Hong Kong account — does not match <b>Nikolaj</b> (Sweden), a legend of psychedelic minimal. Real Padang releases: <b>Cowcaine EP</b> (19/02/2025), track The Portal on Reborn. Bio pending correct SC.',
      es: '<i>Atención: perfil SoundCloud no confirmado.</i> El perfil soundcloud.com/psypox es una cuenta vacía en Hong Kong — no coincide con <b>Nikolaj</b> (Suecia), leyenda del minimal psicodélico. Releases reales en Padang: <b>Cowcaine EP</b> (19/02/2025), track The Portal en Reborn. Bio en validación del SC correcto.',
      de: '<i>Hinweis: SoundCloud-Profil noch nicht bestätigt.</i> Das Profil soundcloud.com/psypox ist ein leerer Account in Hongkong — passt nicht zu <b>Nikolaj</b> (Schweden), einer Legende des psychedelischen Minimal. Echte Padang-Releases: <b>Cowcaine EP</b> (19.02.2025), Track The Portal auf Reborn. Bio in Validierung des korrekten SC.',
      fr: '<i>Attention : profil SoundCloud non confirmé.</i> Le profil soundcloud.com/psypox est un compte vide à Hong Kong — ne correspond pas à <b>Nikolaj</b> (Suède), légende du minimal psychédélique. Vraies sorties Padang : <b>Cowcaine EP</b> (19/02/2025), morceau The Portal sur Reborn. Bio en validation du SC correct.',
      ja: '<i>注意：SoundCloud プロフィールは未確認。</i>soundcloud.com/psypox プロフィールは香港の空のアカウントで、サイケデリック・ミニマルのレジェンドである <b>Nikolaj</b>（スウェーデン）とは一致しない。Padang での実際のリリース：<b>Cowcaine EP</b>（2025年2月19日）、Reborn 収録の The Portal。正しい SC のバイオを確認中。'
    },
    "Stancke": {
      en: '<b>Stancke</b>, Curitiba, Brazil. <b>Live act</b> of <b>Progressive Trance / Zenonesque</b>, a Brazilian producer with a dense, ritualistic sonic identity. <b>On Padang Records:</b> recently released his <b>fourth EP — Neon Manifesto</b>, another chapter of a consistent body of work in dark progressive. <b>Side projects:</b> <a href="https://soundcloud.com/warenhaux" target="_blank" rel="noopener">Warenhaux</a> (Techno) and <a href="https://soundcloud.com/terpenoids-live" target="_blank" rel="noopener">Terpenoids</a> (Forest). Also part of collectives <b>Tríade Trance</b>, <b>Hipnose Crew</b> and <b>Modulation</b>. Recent live sets: <b>Adhana Festival</b>, <b>Tríade Trance Progressive Edition</b>, remixes with Peia (Kromagon, Sensient).',
      es: '<b>Stancke</b>, Curitiba, Brasil. <b>Live act</b> de <b>Progressive Trance / Zenonesque</b>, productor brasileño con identidad sonora densa y ritualística. <b>En Padang Records:</b> recientemente lanzó su <b>cuarto EP — Neon Manifesto</b>, otro capítulo de un cuerpo de trabajo consistente en dark progressive. <b>Side projects:</b> <a href="https://soundcloud.com/warenhaux" target="_blank" rel="noopener">Warenhaux</a> (Techno) y <a href="https://soundcloud.com/terpenoids-live" target="_blank" rel="noopener">Terpenoids</a> (Forest). También integra los colectivos <b>Tríade Trance</b>, <b>Hipnose Crew</b> y <b>Modulation</b>. Live sets recientes: <b>Adhana Festival</b>, <b>Tríade Trance Progressive Edition</b>, remixes con Peia (Kromagon, Sensient).',
      de: '<b>Stancke</b>, Curitiba, Brasilien. <b>Live-Act</b> für <b>Progressive Trance / Zenonesque</b>, brasilianischer Produzent mit dichter, ritueller Klangidentität. <b>Auf Padang Records:</b> kürzlich erschien sein <b>viertes EP — Neon Manifesto</b>, ein weiteres Kapitel eines konsequenten Werkkörpers im Dark Progressive. <b>Side Projects:</b> <a href="https://soundcloud.com/warenhaux" target="_blank" rel="noopener">Warenhaux</a> (Techno) und <a href="https://soundcloud.com/terpenoids-live" target="_blank" rel="noopener">Terpenoids</a> (Forest). Auch Teil der Kollektive <b>Tríade Trance</b>, <b>Hipnose Crew</b> und <b>Modulation</b>. Aktuelle Live-Sets: <b>Adhana Festival</b>, <b>Tríade Trance Progressive Edition</b>, Remixes mit Peia (Kromagon, Sensient).',
      fr: '<b>Stancke</b>, Curitiba, Brésil. <b>Live act</b> de <b>Progressive Trance / Zenonesque</b>, producteur brésilien avec une identité sonore dense et rituelle. <b>Sur Padang Records :</b> a récemment sorti son <b>quatrième EP — Neon Manifesto</b>, un autre chapitre d\'un corps de travail cohérent en dark progressive. <b>Side projects :</b> <a href="https://soundcloud.com/warenhaux" target="_blank" rel="noopener">Warenhaux</a> (Techno) et <a href="https://soundcloud.com/terpenoids-live" target="_blank" rel="noopener">Terpenoids</a> (Forest). Fait également partie des collectifs <b>Tríade Trance</b>, <b>Hipnose Crew</b> et <b>Modulation</b>. Live sets récents : <b>Adhana Festival</b>, <b>Tríade Trance Progressive Edition</b>, remixes avec Peia (Kromagon, Sensient).',
      ja: '<b>Stancke</b>、ブラジル・クリチバ。<b>Progressive Trance / Zenonesque</b> の <b>ライブアクト</b>、密度の高いリチュアルな音響アイデンティティを持つブラジル人プロデューサー。<b>Padang Records から：</b>最近 <b>4枚目の EP「Neon Manifesto」</b>をリリース、ダーク・プログレッシブの一貫した作品群にまた一章を加えた。<b>サイドプロジェクト：</b><a href="https://soundcloud.com/warenhaux" target="_blank" rel="noopener">Warenhaux</a>（Techno）、<a href="https://soundcloud.com/terpenoids-live" target="_blank" rel="noopener">Terpenoids</a>（Forest）。<b>Tríade Trance</b>、<b>Hipnose Crew</b>、<b>Modulation</b> などのコレクティブにも参加。最近のライブ：<b>Adhana Festival</b>、<b>Tríade Trance Progressive Edition</b>、Peia とのリミックス（Kromagon、Sensient）。'
    },
  };

  // ── Hook MutationObserver na modal de roster.html ──
  // Quando .modal recebe class "show", traduz a bio conforme idioma ativo.
  function currentLang() {
    return document.documentElement.lang || 'pt';
  }

  function translateModalBio() {
    const lang = currentLang();
    if (lang === 'pt') return; // PT é source — fica como está
    const nm = document.getElementById('mNm');
    const bio = document.getElementById('mBio');
    if (!nm || !bio) return;
    const artist = (nm.textContent || '').trim();
    const entry = BIOS[artist];
    if (entry && entry[lang]) {
      bio.innerHTML = entry[lang];
    }
  }

  function attach() {
    const modal = document.getElementById('modal');
    if (!modal) { return setTimeout(attach, 100); }
    const obs = new MutationObserver(muts => {
      for (const m of muts) {
        if (m.attributeName === 'class' && modal.classList.contains('show')) {
          // pequeno delay pra garantir que openArtist() já setou mNm e mBio
          setTimeout(translateModalBio, 30);
        }
      }
    });
    obs.observe(modal, { attributes: true, attributeFilter: ['class'] });

    // também re-traduz quando o usuário troca de idioma com a modal aberta
    document.querySelectorAll('.lang-switch button').forEach(btn => {
      btn.addEventListener('click', () => {
        if (modal.classList.contains('show')) {
          setTimeout(translateModalBio, 30);
        }
      });
    });
  }

  // expõe pra eventual uso externo
  window.PADANG_BIOS = BIOS;

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', attach);
  } else {
    attach();
  }
})();
